  1→import { useState } from "react";
  2→import { useNavigate } from "@tanstack/react-router";
  3→import { useAgents, groupByRuntime, type AgentRuntime, type AgentListItem } from "../hooks/use-agents";
  4→import { useAgentActions } from "../hooks/use-agent-actions";
  5→import { AgentCard } from "../components/agent/agent-card";
  6→import { Button } from "../components/ui/button";
  7→import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "../components/ui/dialog";
  8→import { Input } from "../components/ui/input";
  9→import { Label } from "../components/ui/label";
 10→
 11→const RUNTIME_SECTIONS: { runtime: AgentRuntime; title: string; emptyText: string }[] = [
 12→  { runtime: "brain", title: "Brain Agents", emptyText: "No brain agents found. These are system agents that process your conversations and graph." },
 13→  { runtime: "external", title: "External Agents", emptyText: "No external agents yet. Create one to connect an external coding agent via MCP." },
 14→  { runtime: "sandbox", title: "Sandbox Agents", emptyText: "No sandbox agents yet. Configure a sandbox provider in settings to get started." },
 15→];
 16→
 17→type DeleteDialogState = {
 18→  agent: AgentListItem;
 19→  confirmText: string;
 20→};
 21→
 22→export function AgentsPage() {
 23→  const { agents, isLoading, error, refresh } = useAgents();
 24→  const { deleteAgent, isSubmitting } = useAgentActions();
 25→  const [deleteState, setDeleteState] = useState<DeleteDialogState | undefined>();
 26→  const navigate = useNavigate();
 27→
 28→  const grouped = groupByRuntime(agents);
 29→
 30→  async function handleDelete() {
 31→    if (!deleteState) return;
 32→    const success = await deleteAgent(deleteState.agent.id, deleteState.confirmText);
 33→    if (success) {
 34→      setDeleteState(undefined);
 35→      refresh();
 36→    }
 37→  }
 38→
 39→  if (error) {
 40→    return (
 41→      <section className="mx-auto flex max-w-4xl flex-col gap-4 p-6">
 42→        <p className="text-sm text-destructive">Failed to load agents: {error}</p>
 43→      </section>
 44→    );
 45→  }
 46→
 47→  return (
 48→    <section className="mx-auto flex max-w-4xl flex-col gap-4 p-6">
 49→      <div className="flex items-center justify-between">
 50→        <h1 className="text-lg font-semibold">Agents</h1>
 51→        <Button size="sm" onClick={() => void navigate({ to: "/agents/new" })}>
 52→          Create Agent
 53→        </Button>
 54→      </div>
 55→
 56→      {isLoading ? (
 57→        <p className="text-sm text-muted-foreground">Loading agents...</p>
 58→      ) : (
 59→        RUNTIME_SECTIONS.map(({ runtime, title, emptyText }) => {
 60→          const items = grouped[runtime];
 61→          return (
 62→            <div key={runtime} className="flex flex-col gap-2">
 63→              <h2 className="text-sm font-medium text-muted-foreground">
 64→                {title} ({items.length})
 65→              </h2>
 66→              {items.length === 0 ? (
 67→                <p className="rounded-lg border border-dashed border-border p-4 text-center text-xs text-muted-foreground">
 68→                  {emptyText}
 69→                </p>
 70→              ) : (
 71→                items.map((agent) => (
 72→                  <AgentCard
 73→                    key={agent.id}
 74→                    agent={agent}
 75→                    onDelete={(a) => setDeleteState({ agent: a, confirmText: "" })}
 76→                  />
 77→                ))
 78→              )}
 79→            </div>
 80→          );
 81→        })
 82→      )}
 83→
 84→      {deleteState ? (
 85→        <Dialog open onOpenChange={(isOpen) => { if (!isOpen) setDeleteState(undefined); }}>
 86→          <DialogContent className="max-w-sm">
 87→            <DialogHeader>
 88→              <DialogTitle>Delete {deleteState.agent.name}?</DialogTitle>
 89→            </DialogHeader>
 90→            <div className="flex flex-col gap-3">
 91→              <p className="text-xs text-muted-foreground">
 92→                This will permanently remove the agent, its identity, authority scopes, and proxy tokens. Type the agent name to confirm.
 93→              </p>
 94→              <Label htmlFor="confirm-name" className="text-xs">
 95→                Type "{deleteState.agent.name}" to confirm
 96→              </Label>
 97→              <Input
 98→                id="confirm-name"
 99→                value={deleteState.confirmText}
100→                onChange={(e) => setDeleteState({ ...deleteState, confirmText: e.target.value })}
101→                placeholder={deleteState.agent.name}
102→              />
103→            </div>
104→            <DialogFooter>
105→              <Button variant="ghost" size="sm" onClick={() => setDeleteState(undefined)}>
106→                Cancel
107→              </Button>
108→              <Button
109→                variant="destructive"
110→                size="sm"
111→                disabled={deleteState.confirmText !== deleteState.agent.name || isSubmitting}
112→                onClick={handleDelete}
113→              >
114→                Delete
115→              </Button>
116→            </DialogFooter>
117→          </DialogContent>
118→        </Dialog>
119→      ) : undefined}
120→    </section>
121→  );
122→}
