  1→/**
  2→ * Agent Route Handlers
  3→ *
  4→ * HTTP handler factory for the agent CRUD module. Each handler resolves
  5→ * identity from Better Auth session, validates input, delegates to
  6→ * query functions, and returns JSON responses.
  7→ *
  8→ * All handlers follow the wide-event observability pattern via
  9→ * trace.getActiveSpan()?.setAttribute().
 10→ */
 11→import { RecordId } from "surrealdb";
 12→import { trace } from "@opentelemetry/api";
 13→import { HttpError } from "../http/errors";
 14→import { jsonError, jsonResponse } from "../http/response";
 15→import type { ServerDependencies } from "../runtime/types";
 16→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
 17→import { log } from "../telemetry/logger";
 18→import {
 19→  listAgents,
 20→  createAgentTransaction,
 21→  getAgentDetail,
 22→  deleteAgentTransaction,
 23→  checkAgentName,
 24→} from "./agent-queries";
 25→import type { CreateAgentInput } from "./types";
 26→
 27→// ---------------------------------------------------------------------------
 28→// Identity resolution (session -> person -> identity)
 29→// ---------------------------------------------------------------------------
 30→
 31→type IdentityInfo = {
 32→  identityRecord: RecordId<"identity", string>;
 33→};
 34→
 35→async function resolveIdentityFromSession(
 36→  deps: ServerDependencies,
 37→  request: Request,
 38→): Promise<IdentityInfo | Response> {
 39→  const session = await deps.auth.api.getSession({ headers: request.headers });
 40→  if (!session?.user?.id) {
 41→    return jsonError("authentication required", 401);
 42→  }
 43→
 44→  const personRecord = new RecordId("person", session.user.id);
 45→
 46→  const [identityRows] = await deps.surreal.query<[RecordId<"identity", string>[]]>(
 47→    "SELECT VALUE in FROM identity_person WHERE out = $person LIMIT 1;",
 48→    { person: personRecord },
 49→  );
 50→  const identityRecord = identityRows[0] as RecordId<"identity", string> | undefined;
 51→  if (!identityRecord) {
 52→    return jsonError("identity not found for user", 500);
 53→  }
 54→
 55→  return { identityRecord };
 56→}
 57→
 58→// ---------------------------------------------------------------------------
 59→// Shared helpers
 60→// ---------------------------------------------------------------------------
 61→
 62→function isResponse(value: unknown): value is Response {
 63→  return value instanceof Response;
 64→}
 65→
 66→async function resolveWorkspace(
 67→  deps: ServerDependencies,
 68→  workspaceId: string,
 69→  logEvent: string,
 70→): Promise<RecordId<"workspace", string> | Response> {
 71→  try {
 72→    return await resolveWorkspaceRecord(deps.surreal, workspaceId);
 73→  } catch (error) {
 74→    if (error instanceof HttpError) {
 75→      return jsonError(error.message, error.status);
 76→    }
 77→    log.error(logEvent, "Failed to resolve workspace", error, { workspaceId });
 78→    return jsonError("failed to resolve workspace", 500);
 79→  }
 80→}
 81→
 82→const VALID_RUNTIMES: ReadonlySet<string> = new Set(["sandbox", "external"]);
 83→
 84→function isValidRuntime(runtime: unknown): runtime is "sandbox" | "external" {
 85→  return typeof runtime === "string" && VALID_RUNTIMES.has(runtime);
 86→}
 87→
 88→// ---------------------------------------------------------------------------
 89→// Route handler factory
 90→// ---------------------------------------------------------------------------
 91→
 92→export function createAgentRouteHandlers(deps: ServerDependencies) {
 93→  return {
 94→    handleList: (workspaceId: string, request: Request) =>
 95→      handleListAgents(deps, workspaceId, request),
 96→    handleCreate: (workspaceId: string, request: Request) =>
 97→      handleCreateAgent(deps, workspaceId, request),
 98→    handleGetDetail: (workspaceId: string, agentId: string, request: Request) =>
 99→      handleGetAgentDetail(deps, workspaceId, agentId, request),
100→    handleDelete: (workspaceId: string, agentId: string, request: Request) =>
101→      handleDeleteAgent(deps, workspaceId, agentId, request),
102→    handleCheckName: (workspaceId: string, request: Request) =>
103→      handleCheckAgentName(deps, workspaceId, request),
104→  };
105→}
106→
107→// ---------------------------------------------------------------------------
108→// GET /api/workspaces/:workspaceId/agents
109→// ---------------------------------------------------------------------------
110→
111→async function handleListAgents(
112→  deps: ServerDependencies,
113→  workspaceId: string,
114→  request: Request,
115→): Promise<Response> {
116→  const identityOrError = await resolveIdentityFromSession(deps, request);
117→  if (isResponse(identityOrError)) return identityOrError;
118→
119→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "agent.list.workspace_resolve.failed");
120→  if (isResponse(workspaceOrError)) return workspaceOrError;
121→
122→  try {
123→    const agents = await listAgents(deps.surreal, workspaceId);
124→    trace.getActiveSpan()?.setAttribute("agent.list.count", agents.length);
125→    return jsonResponse({ agents }, 200);
126→  } catch (error) {
127→    log.error("agent.list.failed", "Failed to list agents", error, { workspaceId });
128→    return jsonError("failed to list agents", 500);
129→  }
130→}
131→
132→// ---------------------------------------------------------------------------
133→// POST /api/workspaces/:workspaceId/agents
134→// ---------------------------------------------------------------------------
135→
136→async function handleCreateAgent(
137→  deps: ServerDependencies,
138→  workspaceId: string,
139→  request: Request,
140→): Promise<Response> {
141→  const identityOrError = await resolveIdentityFromSession(deps, request);
142→  if (isResponse(identityOrError)) return identityOrError;
143→
144→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "agent.create.workspace_resolve.failed");
145→  if (isResponse(workspaceOrError)) return workspaceOrError;
146→
147→  let body: Record<string, unknown>;
148→  try {
149→    body = await request.json() as Record<string, unknown>;
150→  } catch {
151→    return jsonError("invalid JSON body", 400);
152→  }
153→
154→  // Validate name
155→  const name = body.name;
156→  if (typeof name !== "string" || name.trim().length === 0) {
157→    return jsonError("name_required", 400);
158→  }
159→
160→  // Validate runtime
161→  const runtime = body.runtime;
162→  if (!isValidRuntime(runtime)) {
163→    return jsonError("invalid_runtime", 400);
164→  }
165→
166→  // Sandbox-specific validation
167→  if (runtime === "sandbox") {
168→    // Check workspace has sandbox_provider configured
169→    const [wsRows] = await deps.surreal.query<[Array<{ settings: { sandbox_provider?: string } }>]>(
170→      "SELECT settings FROM $ws;",
171→      { ws: new RecordId("workspace", workspaceId) },
172→    );
173→    const sandboxProvider = wsRows[0]?.settings?.sandbox_provider;
174→    if (!sandboxProvider) {
175→      return jsonError("sandbox_provider_not_configured", 400);
176→    }
177→
178→    // Local provider cannot use image or snapshot
179→    if (sandboxProvider === "local") {
180→      const sandboxConfig = body.sandbox_config as { image?: string; snapshot?: string } | undefined;
181→      if (sandboxConfig?.image || sandboxConfig?.snapshot) {
182→        return jsonError("invalid_sandbox_config", 400);
183→      }
184→    }
185→  }
186→
187→  const input: CreateAgentInput = {
188→    name: name.trim(),
189→    runtime,
190→    ...(body.description && typeof body.description === "string" ? { description: body.description } : {}),
191→    ...(body.model && typeof body.model === "string" ? { model: body.model } : {}),
192→    ...(body.sandbox_config ? { sandbox_config: body.sandbox_config as CreateAgentInput["sandbox_config"] } : {}),
193→    ...(body.authority_scopes ? { authority_scopes: body.authority_scopes as CreateAgentInput["authority_scopes"] } : {}),
194→  };
195→
196→  try {
197→    const result = await createAgentTransaction(deps.surreal, workspaceId, input, new Date());
198→    trace.getActiveSpan()?.setAttribute("agent.create.agent_id", result.agent.id);
199→    trace.getActiveSpan()?.setAttribute("agent.create.runtime", runtime);
200→    return jsonResponse(
201→      {
202→        agent: result.agent,
203→        ...(result.proxy_token ? { proxy_token: result.proxy_token } : {}),
204→        workspace_id: workspaceId,
205→      },
206→      201,
207→    );
208→  } catch (error) {
209→    if (error instanceof HttpError) {
210→      return jsonError(
211→        error.status === 409 ? "agent_name_not_unique" : error.message,
212→        error.status,
213→      );
214→    }
215→    log.error("agent.create.failed", "Failed to create agent", error, { workspaceId });
216→    return jsonError("failed to create agent", 500);
217→  }
218→}
219→
220→// ---------------------------------------------------------------------------
221→// GET /api/workspaces/:workspaceId/agents/:agentId
222→// ---------------------------------------------------------------------------
223→
224→async function handleGetAgentDetail(
225→  deps: ServerDependencies,
226→  workspaceId: string,
227→  agentId: string,
228→  request: Request,
229→): Promise<Response> {
230→  const identityOrError = await resolveIdentityFromSession(deps, request);
231→  if (isResponse(identityOrError)) return identityOrError;
232→
233→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "agent.detail.workspace_resolve.failed");
234→  if (isResponse(workspaceOrError)) return workspaceOrError;
235→
236→  try {
237→    const detail = await getAgentDetail(deps.surreal, workspaceId, agentId);
238→    if (!detail) {
239→      return jsonError("agent not found", 404);
240→    }
241→
242→    trace.getActiveSpan()?.setAttribute("agent.detail.agent_id", agentId);
243→    trace.getActiveSpan()?.setAttribute("agent.detail.session_count", detail.sessions.length);
244→    return jsonResponse(detail, 200);
245→  } catch (error) {
246→    log.error("agent.detail.failed", "Failed to get agent detail", error, { workspaceId, agentId });
247→    return jsonError("failed to get agent detail", 500);
248→  }
249→}
250→
251→// ---------------------------------------------------------------------------
252→// DELETE /api/workspaces/:workspaceId/agents/:agentId
253→// ---------------------------------------------------------------------------
254→
255→async function handleDeleteAgent(
256→  deps: ServerDependencies,
257→  workspaceId: string,
258→  agentId: string,
259→  request: Request,
260→): Promise<Response> {
261→  const identityOrError = await resolveIdentityFromSession(deps, request);
262→  if (isResponse(identityOrError)) return identityOrError;
263→
264→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "agent.delete.workspace_resolve.failed");
265→  if (isResponse(workspaceOrError)) return workspaceOrError;
266→
267→  let body: Record<string, unknown>;
268→  try {
269→    body = await request.json() as Record<string, unknown>;
270→  } catch {
271→    return jsonError("invalid JSON body", 400);
272→  }
273→
274→  const confirmName = body.confirm_name;
275→  if (typeof confirmName !== "string" || confirmName.trim().length === 0) {
276→    return jsonError("confirm_name is required", 400);
277→  }
278→
279→  try {
280→    const result = await deleteAgentTransaction(deps.surreal, workspaceId, agentId, confirmName);
281→    trace.getActiveSpan()?.setAttribute("agent.delete.agent_id", agentId);
282→    return jsonResponse(result, 200);
283→  } catch (error) {
284→    if (error instanceof HttpError) {
285→      return jsonError(error.message, error.status);
286→    }
287→    log.error("agent.delete.failed", "Failed to delete agent", error, { workspaceId, agentId });
288→    return jsonError("failed to delete agent", 500);
289→  }
290→}
291→
292→// ---------------------------------------------------------------------------
293→// GET /api/workspaces/:workspaceId/agents/check-name?name=...
294→// ---------------------------------------------------------------------------
295→
296→async function handleCheckAgentName(
297→  deps: ServerDependencies,
298→  workspaceId: string,
299→  request: Request,
300→): Promise<Response> {
301→  const identityOrError = await resolveIdentityFromSession(deps, request);
302→  if (isResponse(identityOrError)) return identityOrError;
303→
304→  const workspaceOrError = await resolveWorkspace(deps, workspaceId, "agent.check_name.workspace_resolve.failed");
305→  if (isResponse(workspaceOrError)) return workspaceOrError;
306→
307→  const url = new URL(request.url);
308→  const name = url.searchParams.get("name");
309→  if (!name || name.trim().length === 0) {
310→    return jsonError("name query parameter is required", 400);
311→  }
312→
313→  try {
314→    const available = await checkAgentName(deps.surreal, workspaceId, name.trim());
315→    trace.getActiveSpan()?.setAttribute("agent.check_name.available", available);
316→    return jsonResponse({ available }, 200);
317→  } catch (error) {
318→    log.error("agent.check_name.failed", "Failed to check agent name", error, { workspaceId });
319→    return jsonError("failed to check agent name", 500);
320→  }
321→}
