  3→-- BM25 full-text search analyzer (required before any FULLTEXT index)
  4→DEFINE ANALYZER OVERWRITE entity_search
  5→  TOKENIZERS blank, class, camel, punct
  6→  FILTERS snowball(english), lowercase;
  7→
  8→DEFINE TABLE conversation SCHEMAFULL;
  9→DEFINE FIELD createdAt ON conversation TYPE datetime;
 10→DEFINE FIELD updatedAt ON conversation TYPE datetime;
 11→DEFINE FIELD workspace ON conversation TYPE record<workspace>;
 12→DEFINE FIELD source ON conversation TYPE option<string>;
 13→DEFINE FIELD timestamp ON conversation TYPE option<datetime>;
 14→DEFINE FIELD messages ON conversation TYPE option<array<record<message>>>;
 15→DEFINE FIELD title ON conversation TYPE option<string>;
 16→DEFINE FIELD title_source ON conversation TYPE option<string> ASSERT $value = NONE OR $value IN ["message", "entity"];
 17→DEFINE FIELD discusses ON conversation TYPE option<record<project | person | feature | task | decision | question | observation | suggestion>>;
 18→DEFINE INDEX conversation_createdAt ON conversation FIELDS createdAt;
 19→DEFINE INDEX conversation_workspace ON conversation FIELDS workspace;
 20→
 21→DEFINE TABLE message SCHEMAFULL;
 22→DEFINE FIELD conversation ON message TYPE record<conversation>;
 23→DEFINE FIELD role ON message TYPE string ASSERT $value IN ["user", "assistant"];
 24→DEFINE FIELD text ON message TYPE string;
 25→DEFINE FIELD createdAt ON message TYPE datetime;
 26→DEFINE FIELD suggestions ON message TYPE option<array<string>>;
 27→DEFINE FIELD clientMessageId ON message TYPE option<string>;
 28→DEFINE INDEX message_conversation_createdAt ON message FIELDS conversation, createdAt;
 29→DEFINE INDEX OVERWRITE idx_message_fulltext ON message FIELDS text FULLTEXT ANALYZER entity_search BM25(1.2, 0.75);
 30→
 31→DEFINE TABLE entity SCHEMAFULL;
 32→DEFINE FIELD kind ON entity TYPE string ASSERT $value IN ["task", "decision", "question"];
 33→DEFINE FIELD text ON entity TYPE string;
 34→DEFINE FIELD confidence ON entity TYPE float ASSERT $value >= 0 AND $value <= 1;
 35→DEFINE FIELD sourceMessage ON entity TYPE record<message>;
 36→DEFINE FIELD createdAt ON entity TYPE datetime;
 37→DEFINE INDEX entity_createdAt ON entity FIELDS createdAt;
 38→
 39→DEFINE TABLE relationship SCHEMAFULL;
 40→DEFINE FIELD type ON relationship TYPE string ASSERT $value IN ["BELONGS_TO", "DEPENDS_ON"];
 41→DEFINE FIELD fromText ON relationship TYPE string;
 42→DEFINE FIELD toText ON relationship TYPE string;
 43→DEFINE FIELD confidence ON relationship TYPE float ASSERT $value >= 0 AND $value <= 1;
 44→DEFINE FIELD sourceMessage ON relationship TYPE record<message>;
 45→DEFINE FIELD createdAt ON relationship TYPE datetime;
 46→DEFINE INDEX relationship_createdAt ON relationship FIELDS createdAt;
 47→
 48→DEFINE TABLE workspace SCHEMAFULL;
 49→DEFINE FIELD name ON workspace TYPE string;
 50→DEFINE FIELD status ON workspace TYPE string;
 51→DEFINE FIELD description ON workspace TYPE option<string>;
 52→DEFINE FIELD tools ON workspace TYPE option<array<string>>;
 53→DEFINE FIELD onboarding_complete ON workspace TYPE bool;
 54→DEFINE FIELD onboarding_turn_count ON workspace TYPE int;
 55→DEFINE FIELD onboarding_summary_pending ON workspace TYPE bool;
 56→DEFINE FIELD onboarding_started_at ON workspace TYPE datetime;
 57→DEFINE FIELD onboarding_completed_at ON workspace TYPE option<datetime>;
 58→DEFINE FIELD created_at ON workspace TYPE datetime;
 59→DEFINE FIELD updated_at ON workspace TYPE option<datetime>;
 60→DEFINE FIELD repo_path ON workspace TYPE option<string>;
 61→DEFINE FIELD settings ON workspace TYPE option<object>;
 62→DEFINE FIELD settings.observer_skip_deterministic ON workspace TYPE option<bool>;
 63→DEFINE FIELD settings.sandbox_provider ON workspace TYPE option<string>
 64→  ASSERT $value = NONE OR $value IN ['local', 'e2b', 'daytona', 'docker'];
 65→DEFINE FIELD daily_budget_usd ON workspace TYPE option<float>;
 66→DEFINE FIELD evidence_enforcement ON workspace TYPE option<string>
 67→  ASSERT $value = NONE OR $value IN ['bootstrap', 'soft', 'hard'];
 68→DEFINE FIELD evidence_enforcement_threshold ON workspace TYPE option<object>;
 69→DEFINE FIELD evidence_enforcement_threshold.min_decisions ON workspace TYPE option<int>;
 70→DEFINE FIELD evidence_enforcement_threshold.min_tasks ON workspace TYPE option<int>;
 71→DEFINE FIELD min_evidence_age_minutes ON workspace TYPE option<int>;
 72→DEFINE FIELD evidence_enforcement_transitions ON workspace TYPE option<array<object>>;
 73→DEFINE FIELD evidence_enforcement_transitions[*].from ON workspace TYPE string;
