 90→DEFINE FIELD created_at ON project TYPE datetime;
 91→DEFINE FIELD updated_at ON project TYPE option<datetime>;
 92→DEFINE INDEX project_name ON project FIELDS name;
 93→DEFINE INDEX OVERWRITE idx_project_fulltext ON project FIELDS name FULLTEXT ANALYZER entity_search BM25(1.2, 0.75);
