100→DEFINE FIELD description_entries ON feature TYPE option<array<object>>;

  1→import { useState, useCallback } from "react";
  2→import { useNavigate } from "@tanstack/react-router";
  3→import { useAgentActions, type AuthorityScopeInput, type CreateAgentResult } from "../hooks/use-agent-actions";
  4→import { AuthorityScopeForm, AUTHORITY_ACTIONS } from "../components/agent/authority-scope-form";
  5→import { ProxyTokenDialog } from "../components/agent/proxy-token-dialog";
  6→import { Button } from "../components/ui/button";
  7→import { Input } from "../components/ui/input";
  8→import { Label } from "../components/ui/label";
  9→import { Textarea } from "../components/ui/textarea";
 10→
 11→type AgentRuntime = "sandbox" | "external";
 12→
 13→const RUNTIME_OPTIONS: { value: AgentRuntime; title: string; description: string }[] = [
 14→  {
 15→    value: "external",
 16→    title: "External",
 17→    description: "Connect an external coding agent via MCP proxy token.",
 18→  },
 19→  {
 20→    value: "sandbox",
 21→    title: "Sandbox",
 22→    description: "Run an agent in a managed sandbox environment.",
 23→  },
 24→];
 25→
 26→function buildDefaultScopes(): AuthorityScopeInput[] {
 27→  return AUTHORITY_ACTIONS.map(({ action }) => ({ action, permission: "propose" as const }));
 28→}
 29→
 30→export function AgentCreatePage() {
 31→  const navigate = useNavigate();
 32→  const { createAgent, checkName, isSubmitting, error, clearError } = useAgentActions();
 33→
 34→  const [selectedRuntime, setSelectedRuntime] = useState<AgentRuntime | undefined>();
 35→  const [name, setName] = useState("");
 36→  const [description, setDescription] = useState("");
 37→  const [model, setModel] = useState("");
 38→  const [scopes, setScopes] = useState<AuthorityScopeInput[]>(buildDefaultScopes);
 39→  const [nameError, setNameError] = useState<string | undefined>();
 40→  const [createdResult, setCreatedResult] = useState<CreateAgentResult | undefined>();
 41→
 42→  const handleNameBlur = useCallback(async () => {
 43→    if (!name.trim()) {
 44→      setNameError(undefined);
 45→      return;
 46→    }
 47→    const available = await checkName(name.trim());
 48→    if (!available) {
 49→      setNameError("This name is already taken.");
 50→    } else {
 51→      setNameError(undefined);
 52→    }
 53→  }, [name, checkName]);
 54→
 55→  async function handleSubmit(event: React.FormEvent) {
 56→    event.preventDefault();
 57→    if (!selectedRuntime || !name.trim()) return;
 58→
 59→    clearError();
 60→    const result = await createAgent({
 61→      name: name.trim(),
 62→      description: description.trim() || undefined,
 63→      runtime: selectedRuntime,
 64→      model: model.trim() || undefined,
 65→      authority_scopes: scopes,
 66→    });
 67→
 68→    if (result) {
 69→      if (result.proxy_token) {
 70→        setCreatedResult(result);
 71→      } else {
 72→        void navigate({ to: "/agents" });
 73→      }
 74→    }
 75→  }
 76→
 77→  // Step 1: Runtime selection
 78→  if (!selectedRuntime) {
 79→    return (
 80→      <section className="mx-auto flex max-w-2xl flex-col gap-6 p-6">
 81→        <div className="flex items-center justify-between">
 82→          <h1 className="text-lg font-semibold">Create Agent</h1>
 83→        </div>
 84→        <p className="text-sm text-muted-foreground">
 85→          Choose a runtime for your new agent.
 86→        </p>
 87→        <div className="flex flex-col gap-3">
 88→          {RUNTIME_OPTIONS.map(({ value, title, description: desc }) => (
 89→            <button
 90→              key={value}
 91→              type="button"
 92→              className="flex flex-col gap-1 rounded-lg border border-border p-4 text-left transition-colors hover:border-primary hover:bg-muted"
 93→              onClick={() => setSelectedRuntime(value)}
 94→            >
 95→              <span className="text-sm font-medium">{title}</span>
 96→              <span className="text-xs text-muted-foreground">{desc}</span>
 97→            </button>
 98→          ))}
 99→        </div>
100→      </section>
101→    );
102→  }
103→
104→  // Step 2: Creation form
105→  return (
106→    <section className="mx-auto flex max-w-2xl flex-col gap-6 p-6">
107→      <div className="flex items-center justify-between">
108→        <h1 className="text-lg font-semibold">Create {selectedRuntime === "external" ? "External" : "Sandbox"} Agent</h1>
109→        <Button variant="ghost" size="sm" onClick={() => setSelectedRuntime(undefined)}>
110→          Back
111→        </Button>
112→      </div>
113→
114→      <form onSubmit={handleSubmit} className="flex flex-col gap-4">
115→        <div className="flex flex-col gap-1.5">
116→          <Label htmlFor="agent-name">Name</Label>
117→          <Input
118→            id="agent-name"
119→            value={name}
120→            onChange={(e) => setName(e.target.value)}
121→            onBlur={() => void handleNameBlur()}
122→            placeholder="e.g. Coding Agent"
123→          />
124→          {nameError ? (
125→            <p className="text-xs text-destructive">{nameError}</p>
126→          ) : undefined}
127→        </div>
128→
129→        <div className="flex flex-col gap-1.5">
130→          <Label htmlFor="agent-description">Description</Label>
131→          <Textarea
132→            id="agent-description"
133→            value={description}
134→            onChange={(e) => setDescription(e.target.value)}
135→            placeholder="What does this agent do?"
136→            rows={2}
137→          />
138→        </div>
139→
140→        <div className="flex flex-col gap-1.5">
141→          <Label htmlFor="agent-model">Model (optional)</Label>
142→          <Input
143→            id="agent-model"
144→            value={model}
145→            onChange={(e) => setModel(e.target.value)}
146→            placeholder="e.g. claude-sonnet-4-20250514"
147→          />
148→        </div>
149→
150→        <AuthorityScopeForm scopes={scopes} onChange={setScopes} />
151→
152→        {error ? (
153→          <p className="text-xs text-destructive">{error}</p>
154→        ) : undefined}
155→
156→        <div className="flex justify-end gap-2">
157→          <Button
158→            variant="ghost"
159→            size="sm"
160→            type="button"
161→            onClick={() => void navigate({ to: "/agents" })}
162→          >
163→            Cancel
164→          </Button>
165→          <Button
166→            size="sm"
167→            type="submit"
168→            disabled={!name.trim() || isSubmitting}
169→          >
170→            {isSubmitting ? "Creating..." : "Create Agent"}
171→          </Button>
172→        </div>
173→      </form>
174→
175→      {createdResult?.proxy_token ? (
176→        <ProxyTokenDialog
177→          open={true}
178→          token={createdResult.proxy_token}
179→          agentName={createdResult.agent.name}
180→          onClose={() => {
181→            setCreatedResult(undefined);
182→            void navigate({ to: "/agents" });
183→          }}
184→        />
185→      ) : undefined}
186→    </section>
187→  );
188→}
