 18→export function createCreateWorkItemTool(deps: ChatToolDeps) {
 19→  return tool({
 20→    description:
 21→      "Create a task, feature, or project directly in the knowledge graph. Use when the user explicitly requests creation (\"add a task for X\") or during onboarding entity seeding. For uncertain/brainstormed items, prefer suggest_work_items instead.",
 22→    inputSchema: createWorkItemSchema,
 23→    execute: async (input, options) => {
 24→      const { context } = await requireAuthorizedContext(options, "create_task", deps);
 25→      const now = new Date();
 26→
 27→      const entityId = randomUUID();
 28→
 29→      // Hard guard: never create a project with the same name as the workspace
 30→      if (input.kind === "project") {
 31→        const [ws] = await deps.surreal.query<[{ name: string } | undefined]>(
 32→          "SELECT name FROM ONLY $ws;",
 33→          { ws: context.workspaceRecord },
 34→        );
 35→        if (ws && input.title.toLowerCase().trim() === ws.name.toLowerCase().trim()) {
 36→          return {
 37→            error: `"${input.title}" is the workspace name, not a project. Create the user's described items (e.g. Dashboard, Inventory) as projects instead.`,
 38→          };
 39→        }
 40→
 41→        const projectRecord = await createProjectRecord({
 42→          surreal: deps.surreal,
 43→          name: input.title,
 44→          status: "active",
 45→          now,
 46→          workspaceRecord: context.workspaceRecord,
 47→          sourceMessageRecord: context.currentMessageRecord,
 48→        });
 49→
 50→        await seedDescriptionEntry({
 51→          surreal: deps.surreal,
 52→          targetRecord: projectRecord,
 53→          text: input.rationale,
 54→        }).catch(() => undefined);
 55→
 56→        await createExtractionProvenanceEdge({
 57→          surreal: deps.surreal,
 58→          sourceRecord: context.currentMessageRecord,
 59→          targetRecord: projectRecord,
 60→          now,
 61→          confidence: 0.95,
 62→          model: deps.extractionModelId,
 63→          fromText: input.title,
 64→          evidence: context.latestUserText,
 65→          evidenceSourceRecord: context.currentMessageRecord,
 66→        });
 67→
 68→        return {
 69→          entity_id: `project:${projectRecord.id as string}`,
 70→          kind: "project" as const,
 71→          title: input.title,
 72→        };
 73→      }
 74→
 75→      if (input.kind === "task") {
 76→        const taskRecord = new RecordId("task", entityId);
 77→        await deps.surreal.create(taskRecord).content({
 78→          title: input.title,
 79→          status: "open",
 80→          workspace: context.workspaceRecord,
 81→          ...(input.category ? { category: input.category } : {}),
 82→          ...(input.priority ? { priority: input.priority } : {}),
 83→          created_at: now,
 84→          updated_at: now,
 85→        });
 86→
 87→        if (input.project) {
 88→          try {
 89→            const projectRecord = await resolveWorkspaceProjectRecord({
 90→              surreal: deps.surreal,
 91→              workspaceRecord: context.workspaceRecord,
 92→              projectInput: input.project,
 93→            });
 94→            await deps.surreal
 95→              .relate(taskRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
 96→                added_at: now,
 97→              })
 98→              .output("after");
 99→          } catch (err) {
100→            log.error("create_work_item", `failed to link task to project "${input.project}"`, err);
101→          }
102→        }
103→
104→        if (input.feature) {
105→          try {
106→            const featureRecord = await resolveWorkspaceFeatureRecord({
107→              surreal: deps.surreal,
108→              workspaceRecord: context.workspaceRecord,
109→              featureInput: input.feature,
110→            });
111→
112→            await deps.surreal
113→              .relate(featureRecord, new RecordId("has_task", randomUUID()), taskRecord, {
114→                added_at: now,
115→              })
116→              .output("after");
117→
118→            await deps.surreal
119→              .relate(taskRecord, new RecordId("belongs_to", randomUUID()), featureRecord, {
120→                added_at: now,
121→              })
122→              .output("after");
123→          } catch (err) {
124→            log.error("create_work_item", `failed to link task to feature "${input.feature}"`, err);
125→          }
126→        }
127→
128→        await seedDescriptionEntry({
129→          surreal: deps.surreal,
130→          targetRecord: taskRecord,
131→          text: input.rationale,
132→        }).catch(() => undefined);
133→
134→        await createExtractionProvenanceEdge({
135→          surreal: deps.surreal,
136→          sourceRecord: context.currentMessageRecord,
137→          targetRecord: taskRecord,
138→          now,
139→          confidence: 0.95,
140→          model: deps.extractionModelId,
141→          fromText: input.title,
142→          evidence: context.latestUserText,
143→          evidenceSourceRecord: context.currentMessageRecord,
144→        });
145→
146→        return {
147→          entity_id: `task:${entityId}`,
148→          kind: "task" as const,
149→          title: input.title,
150→        };
151→      }
152→
153→      // feature
154→      const featureRecord = new RecordId("feature", entityId);
155→      await deps.surreal.create(featureRecord).content({
156→        name: input.title,
157→        status: "active",
158→        workspace: context.workspaceRecord,
159→        ...(input.category ? { category: input.category } : {}),
160→        created_at: now,
161→        updated_at: now,
162→      });
163→
164→      if (input.project) {
165→        try {
166→          const projectRecord = await resolveWorkspaceProjectRecord({
167→            surreal: deps.surreal,
168→            workspaceRecord: context.workspaceRecord,
169→            projectInput: input.project,
170→          });
171→          await ensureProjectFeatureEdge(deps.surreal, projectRecord, featureRecord, now);
172→
173→          await fireDescriptionUpdates({
174→            surreal: deps.surreal,
175→            extractionModel: deps.extractionModel,
176→            trigger: {
177→              kind: "feature_created",
178→              entity: featureRecord,
179→              summary: `Feature added: ${input.title}`,
180→            },
181→          }).catch(() => undefined);
182→        } catch (err) {
183→          log.error("create_work_item", `failed to link feature to project "${input.project}"`, err);
184→        }
185→      }
186→
187→      await seedDescriptionEntry({
188→        surreal: deps.surreal,
189→        targetRecord: featureRecord,
190→        text: input.rationale,
191→      }).catch(() => undefined);
192→
193→      await createExtractionProvenanceEdge({
194→        surreal: deps.surreal,
195→        sourceRecord: context.currentMessageRecord,
196→        targetRecord: featureRecord,
197→        now,
198→        confidence: 0.95,
199→        model: deps.extractionModelId,
200→        fromText: input.title,
201→        evidence: context.latestUserText,
202→        evidenceSourceRecord: context.currentMessageRecord,
203→      });
204→
205→      return {
206→        entity_id: `feature:${entityId}`,
207→        kind: "feature" as const,
208→        title: input.title,
209→      };
210→    },
211→  });
212→}
