 14→const editableWorkItemTableSchema = z.enum(["task", "feature", "project"]);
 15→
 16→export function createEditWorkItemTool(deps: ChatToolDeps) {
 17→  return tool({
 18→    description:
 19→      "Edit an existing task/feature/project by id. Use for rename or metadata updates. Do NOT use this to create new entities.",
 20→    inputSchema: editWorkItemSchema,
 21→    execute: async (input, options) => {
 22→      const { context } = await requireAuthorizedContext(options, "create_task", deps);
 23→      const now = new Date();
 24→      const workItemRecord = parseRecordIdString(input.id, ["task", "feature", "project"]);
 25→
 26→      const inWorkspace = await isEntityInWorkspace(
 27→        deps.surreal,
 28→        context.workspaceRecord,
 29→        workItemRecord,
 30→      );
 31→      if (!inWorkspace) {
 32→        throw new Error(`work item is not in workspace: ${input.id}`);
 33→      }
 34→
 35→      const tableName = editableWorkItemTableSchema.parse(workItemRecord.table.name);
 36→      const patch: Record<string, unknown> = { updated_at: now };
 37→      const updatedFields: string[] = [];
 38→
 39→      if (input.title) {
 40→        if (tableName === "task") {
 41→          patch.title = input.title;
 42→        } else {
 43→          patch.name = input.title;
 44→        }
 45→        updatedFields.push("title");
 46→      }
 47→
 48→      if (input.status) {
 49→        patch.status = input.status;
 50→        updatedFields.push("status");
 51→      }
 52→
 53→      if (input.category) {
 54→        if (tableName === "project") {
 55→          throw new Error("category is not editable on project");
 56→        }
 57→        patch.category = input.category;
 58→        updatedFields.push("category");
 59→      }
 60→
 61→      if (input.priority) {
 62→        if (tableName !== "task") {
 63→          throw new Error("priority is only editable on task");
 64→        }
 65→        patch.priority = input.priority;
 66→        updatedFields.push("priority");
 67→      }
 68→
 69→      if (updatedFields.length === 0 && !input.rationale) {
 70→        throw new Error("at least one editable field must be provided");
 71→      }
 72→
 73→      if (updatedFields.length > 0) {
 74→        await deps.surreal.update(workItemRecord).merge(patch);
 75→      }
 76→
 77→      if (input.rationale) {
 78→        await seedDescriptionEntry({
 79→          surreal: deps.surreal,
 80→          targetRecord: workItemRecord,
 81→          text: input.rationale,
 82→        });
 83→      }
 84→
 85→      await createExtractionProvenanceEdge({
 86→        surreal: deps.surreal,
 87→        sourceRecord: context.currentMessageRecord,
 88→        targetRecord: workItemRecord,
 89→        now,
 90→        confidence: 0.95,
 91→        model: deps.extractionModelId,
 92→        fromText: input.title ?? input.id,
 93→        evidence: context.latestUserText,
 94→        evidenceSourceRecord: context.currentMessageRecord,
 95→      });
 96→
 97→      const updatedName = await readEntityName(deps.surreal, workItemRecord);
 98→
 99→      return {
100→        entity_id: `${tableName}:${workItemRecord.id as string}`,
101→        kind: tableName,
102→        title: updatedName ?? input.title ?? input.id,
103→        updated_fields: updatedFields,
104→        ...(input.rationale ? { rationale_added: true } : {}),
105→      };
106→    },
107→  });
108→}
