  1→import { useCallback, useState } from "react";
  2→import { useWorkspaceState } from "../stores/workspace-state";
  3→
  4→export type AuthorityPermission = "auto" | "propose" | "blocked";
  5→
  6→export type AuthorityScopeInput = {
  7→  action: string;
  8→  permission: AuthorityPermission;
  9→};
 10→
 11→export type CreateAgentInput = {
 12→  name: string;
 13→  description?: string;
 14→  runtime: "sandbox" | "external";
 15→  model?: string;
 16→  authority_scopes?: AuthorityScopeInput[];
 17→};
 18→
 19→export type CreateAgentResult = {
 20→  agent: {
 21→    id: string;
 22→    name: string;
 23→    description?: string;
 24→    runtime: string;
 25→    model?: string;
 26→    identity_id: string;
 27→    created_at: string;
 28→  };
 29→  proxy_token?: string;
 30→  workspace_id: string;
 31→};
 32→
 33→export type AgentDetailResult = {
 34→  agent: {
 35→    id: string;
 36→    name: string;
 37→    description?: string;
 38→    runtime: string;
 39→    model?: string;
 40→    identity_id: string;
 41→    created_at: string;
 42→  };
 43→  identity: { id: string; name: string; type: string; role?: string };
 44→  authority_scopes: Array<{ action: string; permission: string }>;
 45→  sessions: Array<{
 46→    id: string;
 47→    started_at: string;
 48→    ended_at?: string;
 49→    orchestrator_status?: string;
 50→    summary?: string;
 51→  }>;
 52→};
 53→
 54→type UseAgentActionsReturn = {
 55→  isSubmitting: boolean;
 56→  error?: string;
 57→  createAgent: (input: CreateAgentInput) => Promise<CreateAgentResult | undefined>;
 58→  deleteAgent: (agentId: string, confirmName: string) => Promise<boolean>;
 59→  fetchDetail: (agentId: string) => Promise<AgentDetailResult | undefined>;
 60→  checkName: (name: string) => Promise<boolean>;
 61→  clearError: () => void;
 62→};
 63→
 64→export function buildCreateUrl(workspaceId: string): string {
 65→  return `/api/workspaces/${encodeURIComponent(workspaceId)}/agents`;
 66→}
 67→
 68→export function buildDetailUrl(workspaceId: string, agentId: string): string {
 69→  return `/api/workspaces/${encodeURIComponent(workspaceId)}/agents/${encodeURIComponent(agentId)}`;
 70→}
 71→
 72→export function buildDeleteUrl(workspaceId: string, agentId: string): string {
 73→  return `/api/workspaces/${encodeURIComponent(workspaceId)}/agents/${encodeURIComponent(agentId)}`;
 74→}
 75→
 76→export function buildCheckNameUrl(workspaceId: string, name: string): string {
 77→  return `/api/workspaces/${encodeURIComponent(workspaceId)}/agents/check-name?name=${encodeURIComponent(name)}`;
 78→}
 79→
 80→export function useAgentActions(): UseAgentActionsReturn {
 81→  const workspaceId = useWorkspaceState((s) => s.workspaceId);
 82→  const [isSubmitting, setIsSubmitting] = useState(false);
 83→  const [error, setError] = useState<string | undefined>();
 84→
 85→  const clearError = useCallback(() => setError(undefined), []);
 86→
 87→  const createAgent = useCallback(
 88→    async (input: CreateAgentInput): Promise<CreateAgentResult | undefined> => {
 89→      if (!workspaceId) return undefined;
 90→      setIsSubmitting(true);
 91→      setError(undefined);
 92→      try {
 93→        const response = await fetch(buildCreateUrl(workspaceId), {
 94→          method: "POST",
 95→          headers: { "Content-Type": "application/json" },
 96→          body: JSON.stringify(input),
 97→        });
 98→        if (!response.ok) {
 99→          const body = await response.text();
100→          throw new Error(body);
101→        }
102→        return (await response.json()) as CreateAgentResult;
103→      } catch (err) {
104→        setError(err instanceof Error ? err.message : "Failed to create agent");
105→        return undefined;
106→      } finally {
107→        setIsSubmitting(false);
108→      }
109→    },
110→    [workspaceId],
111→  );
112→
113→  const deleteAgent = useCallback(
114→    async (agentId: string, confirmName: string): Promise<boolean> => {
115→      if (!workspaceId) return false;
116→      setIsSubmitting(true);
117→      setError(undefined);
118→      try {
119→        const response = await fetch(buildDeleteUrl(workspaceId, agentId), {
120→          method: "DELETE",
121→          headers: { "Content-Type": "application/json" },
122→          body: JSON.stringify({ confirm_name: confirmName }),
123→        });
124→        if (!response.ok) {
125→          const body = await response.text();
126→          throw new Error(body);
127→        }
128→        return true;
129→      } catch (err) {
130→        setError(err instanceof Error ? err.message : "Failed to delete agent");
131→        return false;
132→      } finally {
133→        setIsSubmitting(false);
134→      }
135→    },
136→    [workspaceId],
137→  );
138→
139→  const fetchDetail = useCallback(
140→    async (agentId: string): Promise<AgentDetailResult | undefined> => {
141→      if (!workspaceId) return undefined;
142→      try {
143→        const response = await fetch(buildDetailUrl(workspaceId, agentId));
144→        if (!response.ok) {
145→          const body = await response.text();
146→          throw new Error(body);
147→        }
148→        return (await response.json()) as AgentDetailResult;
149→      } catch (err) {
150→        setError(err instanceof Error ? err.message : "Failed to load agent detail");
151→        return undefined;
152→      }
153→    },
154→    [workspaceId],
155→  );
156→
157→  const checkName = useCallback(
158→    async (name: string): Promise<boolean> => {
159→      if (!workspaceId) return false;
160→      try {
161→        const response = await fetch(buildCheckNameUrl(workspaceId, name));
162→        if (!response.ok) return false;
163→        const data = (await response.json()) as { available: boolean };
164→        return data.available;
165→      } catch {
166→        return false;
167→      }
168→    },
169→    [workspaceId],
170→  );
171→
172→  return { isSubmitting, error, createAgent, deleteAgent, fetchDetail, checkName, clearError };
173→}
