 28→
 29→export type ReviewViewModel = {
 30→  viewState: "loading" | "error" | "review" | "accepted" | "rejected";
 31→  errorMessage?: string;
 32→  taskTitle?: string;
 33→  agentSummary?: string;
 34→  rawDiff?: string;
 35→  diffStats?: {
 36→    filesChanged: number;
 37→    insertions: number;
 38→    deletions: number;
 39→  };
 40→  sessionMeta?: {
 41→    orchestratorStatus: string;
 42→    worktreeBranch?: string;
 43→    startedAt?: string;
 44→    lastEventAt?: string;
 45→  };
 46→  acceptDisabled: boolean;
 47→  rejectSubmitDisabled: boolean;
 48→};
 49→
 50→export function deriveReviewViewModel(input: ReviewPageInput): ReviewViewModel {
 51→  if (input.acceptStatus === "success") {
 52→    return { viewState: "accepted", taskTitle: input.reviewData?.taskTitle, acceptDisabled: true, rejectSubmitDisabled: true };
 53→  }
 54→  if (input.rejectStatus === "success") {
 55→    return { viewState: "rejected", taskTitle: input.reviewData?.taskTitle, acceptDisabled: true, rejectSubmitDisabled: true };
 56→  }
 57→  if (input.fetchStatus === "idle" || input.fetchStatus === "pending") {
 58→    return { viewState: "loading", acceptDisabled: true, rejectSubmitDisabled: true };
 59→  }
 60→  if (input.fetchStatus === "error") {
 61→    return { viewState: "error", errorMessage: input.fetchError, acceptDisabled: true, rejectSubmitDisabled: true };
 62→  }
 63→
 64→  const data = input.reviewData;
 65→  const isMutating = input.acceptStatus === "pending" || input.rejectStatus === "pending";
 66→
 67→  return {
 68→    viewState: "review",
 69→    taskTitle: data?.taskTitle,
 70→    agentSummary: undefined,
 71→    rawDiff: data?.diff.rawDiff,
 72→    diffStats: data ? { filesChanged: data.diff.stats.filesChanged, insertions: data.diff.stats.insertions, deletions: data.diff.stats.deletions } : undefined,
 73→    sessionMeta: data ? { orchestratorStatus: data.session.orchestratorStatus, worktreeBranch: data.session.worktreeBranch, startedAt: data.session.startedAt, lastEventAt: data.session.lastEventAt } : undefined,
 74→    acceptDisabled: isMutating,
 75→    rejectSubmitDisabled: isMutating || input.rejectFeedback.trim().length === 0,
 76→  };
 77→}
