  1→/**
  2→ * Agent MCP Route -- Effect boundary for /mcp/agent/:sessionId
  3→ *
  4→ * Handles JSON-RPC requests from sandbox coding agents. Parses the
  5→ * JSON-RPC envelope, resolves auth context, and dispatches to
  6→ * method-specific handlers.
  7→ *
  8→ * Effect boundary: this module performs IO (DB queries, request parsing).
  9→ * Pure logic lives in scope-engine.ts, tools-list-handler.ts, and
 10→ * error-response-builder.ts.
 11→ */
 12→import { RecordId, type Surreal } from "surrealdb";
 13→import type { ServerDependencies } from "../runtime/types";
 14→import { HttpError } from "../http/errors";
 15→import { jsonResponse } from "../http/response";
 16→import { resolveAgentSession, type AgentSessionContext } from "./agent-mcp-auth";
 17→import {
 18→  computeEffectiveScope,
 19→  classifyTools,
 20→  computeAuthorizedBrainWriteTools,
 21→  findBrainWriteIntent,
 22→  type AuthorizedIntentSummary,
 23→  type ClassifiedTool,
 24→  type EffectiveScope,
 25→} from "./scope-engine";
 26→import { buildToolsList, BRAIN_NATIVE_TOOL_NAMES } from "./tools-list-handler";
 27→import { handleToolCall, type ToolCallParams } from "./tools-call-handler";
 28→import { handleCreateIntent } from "./create-intent-handler";
 29→import { handleBrainToolCall } from "./brain-tools-handler";
 30→import {
 31→  BRAIN_READ_TOOL_NAMES,
 32→  BRAIN_WRITE_TOOL_NAMES,
 33→} from "./brain-tool-definitions";
 34→import { buildIntentRequiredError } from "./error-response-builder";
 35→import {
 36→  resolveToolsForIdentity,
 37→  createQueryGrantedTools,
 38→  createToolResolutionCache,
 39→  type ToolResolutionCache,
 40→  type QueryGrantedTools,
 41→} from "../proxy/tool-resolver";
 42→import type { BrainAction } from "../oauth/types";
 43→
 44→// ---------------------------------------------------------------------------
 45→// Types
 46→// ---------------------------------------------------------------------------
 47→
 48→type JsonRpcRequest = {
 49→  readonly jsonrpc: string;
 50→  readonly id: string | number | null;
 51→  readonly method: string;
 52→  readonly params?: Record<string, unknown>;
 53→};
 54→
 55→type JsonRpcResponse = {
 56→  readonly jsonrpc: "2.0";
 57→  readonly id: string | number | null;
 58→  readonly result?: unknown;
 59→  readonly error?: {
 60→    readonly code: number;
 61→    readonly message: string;
 62→    readonly data?: unknown;
 63→  };
 64→};
 65→
 66→type IntentRow = {
 67→  id: RecordId<"intent">;
 68→  authorization_details?: readonly BrainAction[];
 69→};
 70→
 71→// ---------------------------------------------------------------------------
 72→// JSON-RPC helpers (pure)
 73→// ---------------------------------------------------------------------------
 74→
 75→function jsonRpcSuccess(id: string | number | null, result: unknown): JsonRpcResponse {
 76→  return { jsonrpc: "2.0", id, result };
 77→}
 78→
 79→function jsonRpcError(
 80→  id: string | number | null,
 81→  code: number,
 82→  message: string,
 83→  data?: unknown,
 84→): JsonRpcResponse {
 85→  return { jsonrpc: "2.0", id, error: { code, message, ...(data !== undefined ? { data } : {}) } };
 86→}
 87→
 88→// ---------------------------------------------------------------------------
 89→// Query ports (effect boundary)
 90→// ---------------------------------------------------------------------------
 91→
 92→/**
 93→ * Query authorized intents gating a specific agent session.
 94→ * Returns intent summaries with authorization_details for scope computation.
 95→ */
 96→async function querySessionIntents(
 97→  surreal: Surreal,
 98→  sessionId: string,
 99→): Promise<readonly AuthorizedIntentSummary[]> {
100→  const sessionRecord = new RecordId("agent_session", sessionId);
101→
102→  const [rows] = await surreal.query<[IntentRow[]]>(
103→    `SELECT id, authorization_details
104→     FROM intent
105→     WHERE id IN (SELECT VALUE in FROM gates WHERE out = $sess)
106→       AND status = 'authorized';`,
107→    { sess: sessionRecord },
108→  );
109→
110→  return (rows ?? []).map((row) => ({
111→    intentId: row.id.id as string,
112→    authorizationDetails: row.authorization_details ?? [],
113→  }));
114→}
115→
116→// ---------------------------------------------------------------------------
117→// Shared scope computation
118→// ---------------------------------------------------------------------------
119→
120→type ResolvedToolsAndScope = {
121→  readonly classifiedTools: readonly ClassifiedTool[];
122→  readonly effectiveScope: EffectiveScope;
123→};
124→
125→/**
126→ * Resolve intents, compute scope, and classify tools for a session.
127→ * Shared between tools/list and tools/call handlers.
128→ */
129→async function resolveClassifiedTools(
130→  context: AgentSessionContext,
131→  surreal: Surreal,
132→  queryTools: QueryGrantedTools,
133→  toolCache: ToolResolutionCache,
134→): Promise<ResolvedToolsAndScope> {
135→  const intents = await querySessionIntents(surreal, context.sessionId);
136→  const effectiveScope = computeEffectiveScope(intents);
137→  const grantedTools = await resolveToolsForIdentity(
138→    context.identityId,
139→    context.workspaceId,
140→    queryTools,
141→    toolCache,
142→  );
143→  const classifiedTools = classifyTools(grantedTools, effectiveScope, BRAIN_NATIVE_TOOL_NAMES);
144→  return { classifiedTools, effectiveScope };
145→}
146→
147→// ---------------------------------------------------------------------------
148→// Method handlers
149→// ---------------------------------------------------------------------------
150→
151→async function handleToolsList(
152→  context: AgentSessionContext,
153→  surreal: Surreal,
154→  queryTools: QueryGrantedTools,
155→  toolCache: ToolResolutionCache,
156→): Promise<unknown> {
157→  const { classifiedTools, effectiveScope } = await resolveClassifiedTools(context, surreal, queryTools, toolCache);
158→  const authorizedBrainWriteTools = computeAuthorizedBrainWriteTools(effectiveScope, BRAIN_WRITE_TOOL_NAMES);
159→  return buildToolsList(classifiedTools, authorizedBrainWriteTools);
160→}
161→
162→// ---------------------------------------------------------------------------
163→// Route Handler Factory
164→// ---------------------------------------------------------------------------
165→
166→export function createAgentMcpHandler(deps: ServerDependencies) {
167→  const queryTools = createQueryGrantedTools(deps.surreal);
168→  const toolCache = createToolResolutionCache(0); // No cache for agent MCP (fresh every request)
169→
170→  return async (sessionId: string, request: Request): Promise<Response> => {
171→    let requestId: string | number | null = null;
172→
173→    try {
174→      // Parse JSON-RPC envelope
175→      const body = (await request.json()) as JsonRpcRequest;
176→      requestId = body.id ?? null;
177→
178→      if (body.jsonrpc !== "2.0" || !body.method) {
179→        return jsonResponse(
180→          jsonRpcError(requestId, -32600, "Invalid Request"),
181→          400,
182→        );
183→      }
184→
185→      // Resolve auth context (throws HttpError on failure)
186→      const context = await resolveAgentSession(request, deps.surreal);
187→
188→      // Verify the URL session ID matches the resolved session
189→      if (context.sessionId !== sessionId) {
190→        throw new HttpError(404, "Session ID mismatch");
191→      }
192→
193→      // Dispatch by method
194→      switch (body.method) {
195→        case "tools/list": {
196→          const result = await handleToolsList(context, deps.surreal, queryTools, toolCache);
197→          return jsonResponse(jsonRpcSuccess(requestId, result), 200);
198→        }
199→
200→        case "tools/call": {
201→          const toolName = (body.params?.name as string) ?? "";
202→          const toolArgs = body.params?.arguments as Record<string, unknown> ?? {};
203→          const brainToolContext = {
204→            workspaceId: context.workspaceId,
205→            identityId: context.identityId,
206→            sessionId: context.sessionId,
207→          };
208→
209→          // Infrastructure: create_intent
210→          if (toolName === "create_intent") {
211→            const outcome = await handleCreateIntent(
212→              toolArgs,
213→              brainToolContext,
214→              deps.surreal,
215→            );
216→
217→            if (outcome.status === "authorized") {
218→              return jsonResponse(
219→                jsonRpcSuccess(requestId, { status: outcome.status, intentId: outcome.intentId }),
220→                200,
221→              );
222→            }
223→            if (outcome.status === "pending_veto") {
224→              return jsonResponse(
225→                jsonRpcSuccess(requestId, { status: outcome.status, intentId: outcome.intentId }),
226→                200,
227→              );
228→            }
229→            if (outcome.status === "vetoed") {
230→              return jsonResponse(
231→                jsonRpcSuccess(requestId, { status: outcome.status, intentId: outcome.intentId, reason: outcome.reason }),
232→                200,
233→              );
234→            }
235→            return jsonResponse(
236→              jsonRpcError(requestId, -32000, outcome.reason),
237→              500,
238→            );
239→          }
240→
241→          // Brain read tools: always available, execute directly
242→          if (BRAIN_READ_TOOL_NAMES.has(toolName)) {
243→            const callResult = await handleBrainToolCall(
244→              toolName, toolArgs, true, brainToolContext, { surreal: deps.surreal },
245→            );
246→            if (callResult.kind === "success") {
247→              return jsonResponse(jsonRpcSuccess(requestId, callResult.result), 200);
248→            }
249→            return jsonResponse(
250→              jsonRpcError(requestId, callResult.code, callResult.message),
251→              500,
252→            );
253→          }
254→
255→          // Brain write tools: require intent authorization
256→          if (BRAIN_WRITE_TOOL_NAMES.has(toolName)) {
257→            const { effectiveScope } = await resolveClassifiedTools(
258→              context, deps.surreal, queryTools, toolCache,
259→            );
260→            const matchingIntent = findBrainWriteIntent(toolName, effectiveScope);
261→
262→            if (!matchingIntent) {
263→              const intentRequiredError = buildIntentRequiredError(toolName, "brain");
264→              return jsonResponse(
265→                jsonRpcError(requestId, intentRequiredError.code, intentRequiredError.message, intentRequiredError.data),
266→                403,
267→              );
268→            }
269→
270→            const callResult = await handleBrainToolCall(
271→              toolName, toolArgs, false, brainToolContext, { surreal: deps.surreal },
272→            );
273→            if (callResult.kind === "success") {
274→              return jsonResponse(jsonRpcSuccess(requestId, callResult.result), 200);
275→            }
276→            return jsonResponse(
277→              jsonRpcError(requestId, callResult.code, callResult.message),
278→              500,
279→            );
280→          }
281→
282→          // External MCP tools: classify and dispatch
283→          const { classifiedTools } = await resolveClassifiedTools(
284→            context, deps.surreal, queryTools, toolCache,
285→          );
286→          const callParams: ToolCallParams = {
287→            name: toolName,
288→            arguments: body.params?.arguments as Record<string, unknown> | undefined,
289→          };
290→          const callResult = await handleToolCall(
291→            callParams,
292→            classifiedTools,
293→            brainToolContext,
294→            {
295→              surreal: deps.surreal,
296→              mcpClientFactory: deps.mcpClientFactory,
297→              inflight: deps.inflight,
298→            },
299→          );
300→
301→          if (callResult.kind === "success") {
302→            return jsonResponse(jsonRpcSuccess(requestId, callResult.result), 200);
303→          }
304→          // Error response: use appropriate HTTP status
305→          const httpStatus = callResult.code === -32403 ? 403
306→            : callResult.code === -32602 ? 400
307→            : callResult.code === -32601 ? 501
308→            : 500;
309→          return jsonResponse(
310→            jsonRpcError(requestId, callResult.code, callResult.message, callResult.data),
311→            httpStatus,
312→          );
313→        }
314→
315→        case "create_intent": {
316→          // Also handle create_intent as a top-level JSON-RPC method
317→          const intentArgs = body.params ?? {};
318→          const outcome = await handleCreateIntent(
319→            intentArgs,
320→            {
321→              workspaceId: context.workspaceId,
322→              identityId: context.identityId,
323→              sessionId: context.sessionId,
324→            },
325→            deps.surreal,
326→          );
327→
328→          if (outcome.status === "authorized") {
329→            return jsonResponse(
330→              jsonRpcSuccess(requestId, { status: outcome.status, intentId: outcome.intentId }),
331→              200,
332→            );
333→          }
334→          if (outcome.status === "pending_veto") {
335→            return jsonResponse(
336→              jsonRpcSuccess(requestId, { status: outcome.status, intentId: outcome.intentId }),
337→              200,
338→            );
339→          }
340→          if (outcome.status === "vetoed") {
341→            return jsonResponse(
342→              jsonRpcSuccess(requestId, { status: outcome.status, intentId: outcome.intentId, reason: outcome.reason }),
343→              200,
344→            );
345→          }
346→          return jsonResponse(
347→            jsonRpcError(requestId, -32000, outcome.reason),
348→            500,
349→          );
350→        }
351→
352→        default:
353→          return jsonResponse(
354→            jsonRpcError(requestId, -32601, "Method not found"),
355→            404,
356→          );
357→      }
358→    } catch (error) {
359→      if (error instanceof HttpError) {
360→        return jsonResponse(
361→          jsonRpcError(requestId, -32000, error.message),
362→          error.status,
363→        );
364→      }
365→      throw error;
366→    }
367→  };
368→}
