  1→/**
  2→ * AgentStatusSection -- shows agent assignment and live status for tasks.
  3→ *
  4→ * Pure core: deriveAgentStatusView computes what to render from entity + session data.
  5→ * Effect boundary: the component wires useAgentSession for SSE updates and assignAgent for dispatch.
  6→ */
  7→
  8→import { useState } from "react";
  9→import type { AgentSessionSummary, EntityKind } from "../../../shared/contracts";
 10→import { useAgentSession, type AgentSessionStatus } from "../../hooks/use-agent-session";
 11→import { assignAgent, type AssignAgentResponse } from "../../graph/orchestrator-api";
 12→import { useWorkspaceState } from "../../stores/workspace-state";
 13→import { usePublicConfig } from "../../hooks/use-public-config";
 14→import { AgentSessionPanel } from "./AgentSessionPanel";
 15→import { Button } from "../ui/button";
 16→import { Input } from "../ui/input";
 17→import { Badge } from "../ui/badge";
 18→
 19→// ---------------------------------------------------------------------------
 20→// Pure core: view derivation
 21→// ---------------------------------------------------------------------------
 22→
 23→const ASSIGNABLE_STATUSES = new Set(["open", "ready", "todo"]);
 24→
 25→export type AgentStatusViewHidden = { variant: "hidden" };
 26→export type AgentStatusViewAssign = { variant: "assign" };
 27→export type AgentStatusViewActive = {
 28→  variant: "active";
 29→  agentSessionId: string;
 30→  orchestratorStatus: string;
 31→  filesChangedCount: number;
 32→  streamId: string;
 33→  startedAt: string;
 34→};
 35→
 36→export type AgentStatusView =
 37→  | AgentStatusViewHidden
 38→  | AgentStatusViewAssign
 39→  | AgentStatusViewActive;
 40→
 41→export type DeriveAgentStatusInput = {
 42→  entityKind: string;
 43→  entityStatus: string;
 44→  agentSession?: AgentSessionSummary;
 45→};
 46→
 47→export function deriveAgentStatusView(input: DeriveAgentStatusInput): AgentStatusView {
 48→  if (input.entityKind !== "task") {
 49→    return { variant: "hidden" };
 50→  }
 51→
 52→  if (input.agentSession) {
 53→    return {
 54→      variant: "active",
 55→      agentSessionId: input.agentSession.agentSessionId,
 56→      orchestratorStatus: input.agentSession.orchestratorStatus,
 57→      filesChangedCount: input.agentSession.filesChangedCount,
 58→      streamId: input.agentSession.streamId,
 59→      startedAt: input.agentSession.startedAt,
 60→    };
 61→  }
 62→
 63→  if (ASSIGNABLE_STATUSES.has(input.entityStatus)) {
 64→    return { variant: "assign" };
 65→  }
 66→
 67→  return { variant: "hidden" };
 68→}
 69→
 70→// ---------------------------------------------------------------------------
 71→// Repo path banner visibility
 72→// ---------------------------------------------------------------------------
 73→
 74→export function shouldShowRepoPathBanner(input: {
 75→  worktreeManagerEnabled: boolean;
 76→  repoPath: string | undefined;
 77→}): boolean {
 78→  if (!input.worktreeManagerEnabled) return false;
 79→  return input.repoPath === undefined;
 80→}
 81→
 82→// ---------------------------------------------------------------------------
 83→// Status badge display
 84→// ---------------------------------------------------------------------------
 85→
 86→const STATUS_LABELS: Record<AgentSessionStatus, string> = {
 87→  spawning: "Spawning",
 88→  active: "Working",
 89→  idle: "Idle",
 90→  completed: "Completed",
 91→  aborted: "Aborted",
 92→  error: "Error",
 93→};
 94→
 95→const STATUS_VARIANTS: Record<AgentSessionStatus, "default" | "secondary" | "destructive" | "outline"> = {
 96→  spawning: "outline",
 97→  active: "default",
 98→  idle: "secondary",
 99→  completed: "secondary",
100→  aborted: "destructive",
101→  error: "destructive",
102→};
103→
104→function statusLabel(status: AgentSessionStatus): string {
105→  return STATUS_LABELS[status];
106→}
107→
108→// ---------------------------------------------------------------------------
109→// Component
110→// ---------------------------------------------------------------------------
111→
112→export function AgentStatusSection({
113→  entityId,
114→  workspaceId,
115→  entityKind,
116→  entityStatus,
117→  agentSession,
118→}: {
119→  entityId: string;
120→  workspaceId: string;
121→  entityKind: EntityKind;
122→  entityStatus: string;
123→  agentSession?: AgentSessionSummary;
124→}) {
125→  const repoPath = useWorkspaceState((s) => s.repoPath);
126→  const setStoreRepoPath = useWorkspaceState((s) => s.setRepoPath);
127→  const config = usePublicConfig();
128→  const [assigning, setAssigning] = useState(false);
129→  const [assignError, setAssignError] = useState<string | undefined>();
130→  const [assignResult, setAssignResult] = useState<AssignAgentResponse | undefined>();
131→  const [repoPathInput, setRepoPathInput] = useState("");
132→  const [settingRepoPath, setSettingRepoPath] = useState(false);
133→  const [repoPathError, setRepoPathError] = useState<string | undefined>();
134→
135→  const initialView = deriveAgentStatusView({ entityKind, entityStatus, agentSession });
136→
137→  const streamUrl = assignResult?.streamUrl ?? (
138→    initialView.variant === "active"
139→      ? `/api/orchestrator/${encodeURIComponent(workspaceId)}/sessions/${encodeURIComponent(initialView.agentSessionId)}/stream`
140→      : undefined
141→  );
142→  const startedAt = initialView.variant === "active" ? initialView.startedAt : new Date().toISOString();
143→
144→  const { state: sessionState } = useAgentSession(streamUrl, startedAt);
145→
146→  const hasActiveStream = streamUrl !== undefined;
147→
148→  if (initialView.variant === "hidden" && !hasActiveStream) {
149→    return undefined;
150→  }
151→
152→  async function handleAssign() {
153→    if (assigning) return;
154→    setAssigning(true);
155→    setAssignError(undefined);
156→    try {
157→      const rawTaskId = entityId.includes(":") ? entityId.split(":")[1] : entityId;
158→      const result = await assignAgent(workspaceId, rawTaskId);
159→      setAssignResult(result);
160→    } catch (err) {
161→      setAssignError(err instanceof Error ? err.message : "Failed to assign agent");
162→    } finally {
163→      setAssigning(false);
164→    }
165→  }
166→
167→  if (hasActiveStream) {
168→    const displayStatus = sessionState.status;
169→    const displayFiles = initialView.variant === "active"
170→      ? initialView.filesChangedCount + sessionState.filesChanged
171→      : sessionState.filesChanged;
172→
173→    const currentSessionId = assignResult?.agentSessionId
174→      ?? (initialView.variant === "active" ? initialView.agentSessionId : "");
175→
176→    return (
177→      <div className="flex flex-col gap-2 px-4">
178→        <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Agent</h4>
179→        <div className="flex items-center gap-2">
180→          <Badge variant={STATUS_VARIANTS[displayStatus]} data-testid="agent-status-badge">
181→            {statusLabel(displayStatus)}
182→          </Badge>
183→          {displayFiles > 0 ? (
184→            <span className="text-xs text-muted-foreground" data-testid="agent-file-count">
185→              {displayFiles} file{displayFiles !== 1 ? "s" : ""} changed
186→            </span>
187→          ) : undefined}
188→        </div>
189→        <AgentSessionPanel
190→          workspaceId={workspaceId}
191→          agentSessionId={currentSessionId}
192→          sessionStatus={displayStatus}
193→          outputEntries={sessionState.outputEntries}
194→          stallWarning={sessionState.stallWarning}
195→          connectionError={sessionState.connectionError}
196→        />
197→        {displayStatus === "idle" ? (
198→          <a
199→            className="text-xs font-medium text-ring hover:underline"
200→            data-testid="agent-review-link"
201→            href={`/review/${encodeURIComponent(currentSessionId)}`}
202→          >
203→            Review
204→          </a>
205→        ) : undefined}
206→      </div>
207→    );
208→  }
209→
210→  if (initialView.variant === "assign") {
211→    const missingRepoPath = shouldShowRepoPathBanner({
212→      worktreeManagerEnabled: config.worktreeManagerEnabled,
213→      repoPath,
214→    });
215→
216→    return (
217→      <div className="flex flex-col gap-2 px-4">
218→        <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Agent</h4>
219→        {missingRepoPath ? (
220→          <div className="flex flex-col gap-2 rounded-md border border-border bg-muted p-3" data-testid="agent-repo-path-banner">
221→            <p className="text-xs text-muted-foreground">Repository path is not configured for this workspace. Set it before assigning an agent.</p>
222→            <form
223→              className="flex items-center gap-1.5"
224→              data-testid="agent-repo-path-form"
225→              onSubmit={async (e) => {
226→                e.preventDefault();
227→                const trimmed = repoPathInput.trim();
228→                if (!trimmed || settingRepoPath) return;
229→                setSettingRepoPath(true);
230→                setRepoPathError(undefined);
231→                try {
232→                  const res = await fetch(`/api/workspaces/${encodeURIComponent(workspaceId)}/repo-path`, {
233→                    method: "POST",
234→                    headers: { "Content-Type": "application/json" },
235→                    body: JSON.stringify({ path: trimmed }),
236→                  });
237→                  if (!res.ok) {
238→                    const body = await res.json().catch(() => ({ error: "Failed to set repository path" }));
239→                    setRepoPathError(body.error ?? "Failed to set repository path");
240→                    return;
241→                  }
242→                  setStoreRepoPath(trimmed);
243→                  setRepoPathInput("");
244→                } catch {
245→                  setRepoPathError("Network error");
246→                } finally {
247→                  setSettingRepoPath(false);
248→                }
249→              }}
250→            >
251→              <Input
252→                type="text"
253→                data-testid="agent-repo-path-input"
254→                placeholder="/path/to/git/repository"
255→                value={repoPathInput}
256→                onChange={(e) => setRepoPathInput(e.target.value)}
257→                disabled={settingRepoPath}
258→                className="h-7 flex-1 text-xs"
259→              />
260→              <Button
261→                type="submit"
262→                size="xs"
263→                data-testid="agent-repo-path-action"
264→                disabled={settingRepoPath || repoPathInput.trim().length === 0}
265→              >
266→                {settingRepoPath ? "Setting..." : "Set Path"}
267→              </Button>
268→            </form>
269→            {repoPathError ? (
270→              <p className="text-xs text-destructive" data-testid="agent-repo-path-error">{repoPathError}</p>
271→            ) : undefined}
272→          </div>
273→        ) : undefined}
274→        <Button
275→          variant="outline"
276→          size="sm"
277→          data-testid="agent-assign-button"
278→          disabled={assigning || missingRepoPath}
279→          onClick={handleAssign}
280→        >
281→          {assigning ? "Assigning..." : "Assign Agent"}
282→        </Button>
283→        {assignError ? (
284→          <p className="text-xs text-destructive" data-testid="agent-assign-error">{assignError}</p>
285→        ) : undefined}
286→      </div>
287→    );
288→  }
289→
290→  return undefined;
291→}
