  1→import { tool } from "ai";
  2→import type { EntityCategory } from "../../shared/contracts";
  3→import { searchEntitiesByBm25 } from "../graph/bm25-search";
  4→import { requireAuthorizedContext } from "../iam/authority";
  5→import { suggestWorkItemsSchema } from "../mcp/brain-tool-definitions";
  6→import type { ChatToolDeps } from "./types";
  7→
  8→type SuggestedWorkItem = {
  9→  kind: "task" | "feature" | "project";
 10→  title: string;
 11→  rationale: string;
 12→  category?: EntityCategory;
 13→  project?: string;
 14→  priority?: string;
 15→  possible_duplicate?: {
 16→    id: string;
 17→    name: string;
 18→    similarity: number;
 19→  };
 20→};
 21→
 22→type UpdatedWorkItem = {
 23→  existing_id: string;
 24→  title: string;
 25→  changes: string;
 26→};
 27→
 28→type DiscardedWorkItem = {
 29→  title: string;
 30→  reason: string;
 31→};
 32→
 33→const CLOSED_STATUSES = new Set(["done", "completed", "closed", "resolved", "superseded"]);
 34→
 35→export function createSuggestWorkItemsTool(deps: ChatToolDeps) {
 36→  return tool({
 37→    description:
 38→      "Process a batch of proposed work items and return issue-style PM triage buckets: suggestions, updated, discarded.",
 39→    inputSchema: suggestWorkItemsSchema,
 40→    execute: async (input, options) => {
 41→      const { context } = await requireAuthorizedContext(options, "create_suggestion", deps);
 42→      const suggestions: SuggestedWorkItem[] = [];
 43→      const updated: UpdatedWorkItem[] = [];
 44→      const discarded: DiscardedWorkItem[] = [];
 45→
 46→      for (const item of input.items) {
 47→        const suggestion: SuggestedWorkItem = {
 48→          kind: item.kind,
 49→          title: item.title,
 50→          rationale: item.rationale,
 51→          ...(item.category ? { category: item.category } : {}),
 52→          ...(item.project ? { project: item.project } : {}),
 53→          ...(item.priority ? { priority: item.priority } : {}),
 54→        };
 55→
 56→        // BM25 text search for duplicate detection -- replaces embedding similarity
 57→        const candidates = await searchEntitiesByBm25({
 58→          surreal: deps.surreal,
 59→          workspaceRecord: context.workspaceRecord,
 60→          query: item.title,
 61→          kinds: [item.kind],
 62→          limit: 5,
 63→        });
 64→
 65→        const top = candidates[0];
 66→        if (!top) {
 67→          suggestions.push(suggestion);
 68→          continue;
 69→        }
 70→
 71→        const normalizedTopStatus = top.status ? top.status.trim().toLowerCase() : undefined;
 72→        if (normalizedTopStatus && CLOSED_STATUSES.has(normalizedTopStatus)) {
 73→          suggestions.push(suggestion);
 74→          continue;
 75→        }
 76→
 77→        // BM25 duplicate detection: exact title match = discard, partial match = merge
 78→        const normalizedTopName = top.name.trim().toLowerCase();
 79→        const normalizedTitle = item.title.trim().toLowerCase();
 80→
 81→        if (normalizedTopName === normalizedTitle) {
 82→          discarded.push({
 83→            title: item.title,
 84→            reason: `Exact duplicate of existing item ${top.kind}:${top.id} (${top.name})`,
 85→          });
 86→          continue;
 87→        }
 88→
 89→        // BM25 match means significant keyword overlap -- suggest merge
 90→        updated.push({
 91→          existing_id: `${top.kind}:${top.id}`,
 92→          title: top.name,
 93→          changes: `Merge context from suggested item '${item.title}'`,
 94→        });
 95→      }
 96→
 97→      return {
 98→        suggestions,
 99→        updated,
100→        discarded,
101→      };
102→    },
103→  });
104→}
