  1→/**
  2→ * Typed fetch wrappers for orchestrator endpoints.
  3→ *
  4→ * Follows the same error-handling pattern as graph/actions.ts:
  5→ * throw on non-OK responses with status and message.
  6→ */
  7→
  8→// ---------------------------------------------------------------------------
  9→// Response Types
 10→// ---------------------------------------------------------------------------
 11→
 12→export type AssignAgentResponse = {
 13→  agentSessionId: string;
 14→  streamId: string;
 15→  streamUrl: string;
 16→};
 17→
 18→export type SessionStatusResponse = {
 19→  agentSessionId: string;
 20→  orchestratorStatus: string;
 21→  worktreeBranch?: string;
 22→  startedAt: string;
 23→  lastEventAt?: string;
 24→};
 25→
 26→export type SessionReviewResponse = {
 27→  taskTitle: string;
 28→  diff: {
 29→    files: Array<{
 30→      path: string;
 31→      status: "added" | "modified" | "deleted";
 32→      additions: number;
 33→      deletions: number;
 34→    }>;
 35→    rawDiff: string;
 36→    stats: {
 37→      filesChanged: number;
 38→      insertions: number;
 39→      deletions: number;
 40→    };
 41→  };
 42→  session: {
 43→    orchestratorStatus: string;
 44→    worktreeBranch?: string;
 45→    startedAt?: string;
 46→    lastEventAt?: string;
 47→    toolCallCount?: number;
 48→    filesEdited?: number;
 49→  };
 50→};
 51→
 52→export type AcceptSessionResponse = {
 53→  accepted: boolean;
 54→  taskStatus: string;
 55→};
 56→
 57→export type RejectSessionResponse = {
 58→  rejected: boolean;
 59→  continuing: boolean;
 60→};
 61→
 62→export type AbortSessionResponse = {
 63→  aborted: boolean;
 64→  taskStatus: string;
 65→};
 66→
 67→export type SendPromptResponse = {
 68→  delivered: boolean;
 69→};
 70→
 71→// ---------------------------------------------------------------------------
 72→// Structured Error
 73→// ---------------------------------------------------------------------------
 74→
 75→export type OrchestratorErrorCode =
 76→  | "SESSION_NOT_FOUND"
 77→  | "SESSION_ERROR"
 78→  | "TASK_NOT_FOUND"
 79→  | "TASK_NOT_ASSIGNABLE"
 80→  | "BAD_REQUEST"
 81→  | "SERVER_ERROR"
 82→  | "UNKNOWN_ERROR";
 83→
 84→export class OrchestratorError extends Error {
 85→  readonly code: OrchestratorErrorCode;
 86→  readonly httpStatus: number;
 87→
 88→  constructor(code: OrchestratorErrorCode, message: string, httpStatus: number) {
 89→    super(message);
 90→    this.name = "OrchestratorError";
 91→    this.code = code;
 92→    this.httpStatus = httpStatus;
 93→  }
 94→}
 95→
 96→function mapHttpStatusToErrorCode(httpStatus: number): OrchestratorErrorCode {
 97→  switch (httpStatus) {
 98→    case 400: return "BAD_REQUEST";
 99→    case 404: return "SESSION_NOT_FOUND";
100→    case 409: return "SESSION_ERROR";
101→    default: return httpStatus >= 500 ? "SERVER_ERROR" : "UNKNOWN_ERROR";
102→  }
103→}
104→
105→// ---------------------------------------------------------------------------
106→// Internal Helpers
107→// ---------------------------------------------------------------------------
108→
109→function buildOrchestratorUrl(workspaceId: string, ...segments: string[]): string {
110→  const base = `/api/orchestrator/${encodeURIComponent(workspaceId)}`;
111→  if (segments.length === 0) return base;
112→  return `${base}/${segments.map(encodeURIComponent).join("/")}`;
113→}
114→
115→async function orchestratorFetch<T>(url: string, init?: RequestInit): Promise<T> {
116→  const response = await fetch(url, init);
117→  if (!response.ok) {
118→    const text = await response.text();
119→    const code = mapHttpStatusToErrorCode(response.status);
120→    throw new OrchestratorError(code, text, response.status);
121→  }
122→  return (await response.json()) as T;
123→}
124→
125→// ---------------------------------------------------------------------------
126→// API Functions
127→// ---------------------------------------------------------------------------
128→
129→export function assignAgent(
130→  workspaceId: string,
131→  taskId: string,
132→): Promise<AssignAgentResponse> {
133→  return orchestratorFetch<AssignAgentResponse>(
134→    buildOrchestratorUrl(workspaceId, "assign"),
135→    {
136→      method: "POST",
137→      headers: { "Content-Type": "application/json" },
138→      body: JSON.stringify({ taskId }),
139→    },
140→  );
141→}
142→
143→export function getSessionStatus(
144→  workspaceId: string,
145→  sessionId: string,
146→): Promise<SessionStatusResponse> {
147→  return orchestratorFetch<SessionStatusResponse>(
148→    buildOrchestratorUrl(workspaceId, "sessions", sessionId),
149→  );
150→}
151→
152→export function getSessionReview(
153→  workspaceId: string,
154→  sessionId: string,
155→): Promise<SessionReviewResponse> {
156→  return orchestratorFetch<SessionReviewResponse>(
157→    buildOrchestratorUrl(workspaceId, "sessions", sessionId, "review"),
158→  );
159→}
160→
161→export function acceptSession(
162→  workspaceId: string,
163→  sessionId: string,
164→  summary?: string,
165→): Promise<AcceptSessionResponse> {
166→  return orchestratorFetch<AcceptSessionResponse>(
167→    buildOrchestratorUrl(workspaceId, "sessions", sessionId, "accept"),
168→    {
169→      method: "POST",
170→      headers: { "Content-Type": "application/json" },
