  1→import { RecordId } from "surrealdb";
  2→import { ENTITY_PRIORITIES, type EntityActionRequest } from "../../shared/contracts";
  3→import { HttpError } from "../http/errors";
  4→import { jsonError, jsonResponse } from "../http/response";
  5→import { acknowledgeObservation, resolveObservation } from "../observation/queries";
  6→import { acceptSuggestion, convertSuggestion, dismissSuggestion, deferSuggestion } from "../suggestion/queries";
  7→import type { ServerDependencies } from "../runtime/types";
  8→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
  9→import {
 10→  confirmDecisionRecord,
 11→  isEntityInWorkspace,
 12→  parseRecordIdString,
 13→  type GraphEntityTable,
 14→} from "../graph/queries";
 15→import { fireDescriptionUpdates } from "../descriptions/triggers";
 16→import { log } from "../telemetry/logger";
 17→
 18→type EntityActionTable = GraphEntityTable | "observation";
 19→
 20→export function createEntityActionsHandler(
 21→  deps: ServerDependencies,
 22→): (entityId: string, request: Request) => Promise<Response> {
 23→  return (entityId: string, request: Request) => handleEntityAction(deps, entityId, request);
 24→}
 25→
 26→async function handleEntityAction(
 27→  deps: ServerDependencies,
 28→  entityId: string,
 29→  request: Request,
 30→): Promise<Response> {
 31→  let body: EntityActionRequest;
 32→  try {
 33→    body = await request.json() as EntityActionRequest;
 34→  } catch {
 35→    return jsonError("invalid JSON body", 400);
 36→  }
 37→
 38→  if (!body.action || !["confirm", "override", "complete", "set_priority", "acknowledge", "resolve", "dismiss", "accept", "defer", "convert"].includes(body.action)) {
 39→    return jsonError("action must be one of: confirm, override, complete, set_priority, acknowledge, resolve, dismiss, accept, defer, convert", 400);
 40→  }
 41→
 42→  const url = new URL(request.url);
 43→  const workspaceId = url.searchParams.get("workspaceId")?.trim();
 44→  if (!workspaceId) {
 45→    return jsonError("workspaceId is required", 400);
 46→  }
 47→
 48→  let workspaceRecord;
 49→  try {
 50→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 51→  } catch (error) {
 52→    if (error instanceof HttpError) {
 53→      return jsonError(error.message, error.status);
 54→    }
 55→    log.error("entity.action.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
 56→    return jsonError("failed to resolve workspace", 500);
 57→  }
 58→
 59→  try {
 60→    const entityTables: EntityActionTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question", "observation", "suggestion"];
 61→    const entityRecord = parseRecordIdString(entityId, entityTables);
 62→
 63→    const table = entityRecord.table.name;
 64→    const now = new Date();
 65→
 66→    // Observation actions have separate handlers from task/decision/question.
 67→    if (table === "observation") {
 68→      if (body.action === "acknowledge") {
 69→        await acknowledgeObservation({
 70→          surreal: deps.surreal,
 71→          workspaceRecord,
 72→          observationRecord: entityRecord as RecordId<"observation", string>,
 73→          now,
 74→        });
 75→        log.info("entity.action.acknowledge", "Observation acknowledged", { workspaceId, entityId });
 76→        return jsonResponse({ status: "acknowledged" }, 200);
 77→      }
 78→
 79→      if (body.action === "resolve") {
 80→        await resolveObservation({
 81→          surreal: deps.surreal,
 82→          workspaceRecord,
 83→          observationRecord: entityRecord as RecordId<"observation", string>,
 84→          now,
 85→        });
 86→        log.info("entity.action.resolve", "Observation resolved", { workspaceId, entityId });
 87→        return jsonResponse({ status: "resolved" }, 200);
 88→      }
 89→
 90→      return jsonError(`action '${body.action}' is not valid for entity type 'observation'`, 400);
 91→    }
 92→
 93→    // Suggestion actions handle their own workspace validation internally.
 94→    if (table === "suggestion") {
 95→      if (body.action === "accept") {
 96→        await acceptSuggestion({
 97→          surreal: deps.surreal,
 98→          workspaceRecord,
 99→          suggestionRecord: entityRecord as RecordId<"suggestion", string>,
100→          now,
101→        });
102→        log.info("entity.action.accept", "Suggestion accepted", { workspaceId, entityId });
103→        return jsonResponse({ status: "accepted" }, 200);
104→      }
105→
106→      if (body.action === "dismiss") {
107→        await dismissSuggestion({
108→          surreal: deps.surreal,
109→          workspaceRecord,
110→          suggestionRecord: entityRecord as RecordId<"suggestion", string>,
111→          now,
112→        });
113→        log.info("entity.action.dismiss", "Suggestion dismissed", { workspaceId, entityId });
114→        return jsonResponse({ status: "dismissed" }, 200);
115→      }
116→
117→      if (body.action === "defer") {
118→        await deferSuggestion({
119→          surreal: deps.surreal,
120→          workspaceRecord,
121→          suggestionRecord: entityRecord as RecordId<"suggestion", string>,
122→          now,
123→        });
124→        log.info("entity.action.defer", "Suggestion deferred", { workspaceId, entityId });
125→        return jsonResponse({ status: "deferred" }, 200);
126→      }
127→
128→      if (body.action === "convert") {
129→        if (!body.convertTo || !["task", "feature", "decision", "project"].includes(body.convertTo)) {
130→          return jsonError("convertTo must be one of: task, feature, decision, project", 400);
131→        }
132→        const result = await convertSuggestion({
133→          surreal: deps.surreal,
134→          workspaceRecord,
135→          suggestionRecord: entityRecord as RecordId<"suggestion", string>,
136→          targetKind: body.convertTo as "task" | "feature" | "decision" | "project",
137→          title: body.convertTitle,
138→          now,
139→        });
140→        log.info("entity.action.convert", "Suggestion converted", { workspaceId, suggestionId: entityId, convertedEntityId: result.entityId, table: result.table });
141→        return jsonResponse({ status: "converted", entityId: result.entityId, table: result.table }, 201);
142→      }
143→
144→      return jsonError(`action '${body.action}' is not valid for entity type 'suggestion'`, 400);
145→    }
146→
147→    const scoped = await isEntityInWorkspace(deps.surreal, workspaceRecord, entityRecord as RecordId<GraphEntityTable, string>);
148→    if (!scoped) {
149→      return jsonError("entity is outside the current workspace scope", 403);
150→    }
151→
152→    if (body.action === "confirm" && table === "decision") {
153→      const [decisionRows] = await deps.surreal
154→        .query<[Array<{ summary: string }>]>(
155→          "SELECT summary FROM $record LIMIT 1;",
156→          { record: entityRecord },
157→        )
158→        .collect<[Array<{ summary: string }>]>();
159→      const decisionSummary = decisionRows[0]?.summary ?? entityId;
160→
161→      await confirmDecisionRecord({
162→        surreal: deps.surreal,
163→        decisionRecord: entityRecord as RecordId<"decision", string>,
164→        confirmedAt: now,
165→        notes: body.notes,
166→      });
167→
168→      deps.inflight.track(fireDescriptionUpdates({
169→        surreal: deps.surreal,
170→        extractionModel: deps.extractionModel,
171→        trigger: {
172→          kind: "decision_confirmed",
173→          entity: entityRecord,
174→          summary: `Decision confirmed: ${decisionSummary}`,
175→        },
176→      }).catch(() => undefined));
177→
178→      log.info("entity.action.confirm", "Decision confirmed", { workspaceId, entityId });
179→      return jsonResponse({ status: "confirmed" }, 200);
180→    }
181→
182→    if (body.action === "override" && table === "decision") {
183→      if (!body.newSummary) {
184→        return jsonError("newSummary is required for override action", 400);
185→      }
186→      await deps.surreal.update(entityRecord as RecordId<"decision", string>).merge({
187→        summary: body.newSummary,
188→        status: "overridden",
189→        updated_at: now,
190→        ...(body.notes ? { override_notes: body.notes } : {}),
191→      });
192→      log.info("entity.action.override", "Decision overridden", { workspaceId, entityId });
193→      return jsonResponse({ status: "overridden" }, 200);
194→    }
195→
196→    if (body.action === "complete" && table === "feature") {
197→      const [featureRows] = await deps.surreal
198→        .query<[Array<{ name: string }>]>(
199→          "SELECT name FROM $record LIMIT 1;",
200→          { record: entityRecord },
201→        )
202→        .collect<[Array<{ name: string }>]>();
203→      const featureName = featureRows[0]?.name ?? entityId;
204→
205→      await deps.surreal.update(entityRecord as RecordId<"feature", string>).merge({
206→        status: "done",
207→        updated_at: now,
208→      });
209→
210→      deps.inflight.track(fireDescriptionUpdates({
211→        surreal: deps.surreal,
212→        extractionModel: deps.extractionModel,
213→        trigger: {
214→          kind: "feature_completed",
215→          entity: entityRecord,
216→          summary: `Feature completed: ${featureName}`,
217→        },
218→      }).catch(() => undefined));
219→
220→      log.info("entity.action.complete", "Feature completed", { workspaceId, entityId });
221→      return jsonResponse({ status: "completed" }, 200);
222→    }
223→
224→    if (body.action === "complete" && table === "task") {
225→      const [taskRows] = await deps.surreal
226→        .query<[Array<{ title: string }>]>(
227→          "SELECT title FROM $record LIMIT 1;",
228→          { record: entityRecord },
229→        )
230→        .collect<[Array<{ title: string }>]>();
231→      const taskTitle = taskRows[0]?.title ?? entityId;
232→
233→      await deps.surreal.update(entityRecord as RecordId<"task", string>).merge({
234→        status: "done",
235→        completed_at: now,
236→        updated_at: now,
237→      });
238→
239→      deps.inflight.track(fireDescriptionUpdates({
240→        surreal: deps.surreal,
241→        extractionModel: deps.extractionModel,
242→        trigger: {
243→          kind: "task_completed",
244→          entity: entityRecord,
245→          summary: `Task completed: ${taskTitle}`,
246→        },
247→      }).catch(() => undefined));
248→
249→      log.info("entity.action.complete", "Task completed", { workspaceId, entityId });
250→      return jsonResponse({ status: "completed" }, 200);
251→    }
252→
253→    if (body.action === "dismiss" && table === "question") {
254→      await deps.surreal.update(entityRecord as RecordId<"question", string>).merge({
255→        status: "dismissed",
256→        updated_at: now,
257→      });
258→      log.info("entity.action.dismiss", "Question dismissed", { workspaceId, entityId });
259→      return jsonResponse({ status: "dismissed" }, 200);
260→    }
261→
262→    if (body.action === "set_priority" && (table === "task" || table === "decision" || table === "question")) {
263→      if (!body.priority || !(ENTITY_PRIORITIES as readonly string[]).includes(body.priority)) {
264→        return jsonError("priority must be one of: low, medium, high, critical", 400);
265→      }
266→      await deps.surreal.update(entityRecord).merge({
267→        priority: body.priority,
268→        updated_at: now,
269→      });
270→      log.info("entity.action.set_priority", "Priority updated", { workspaceId, entityId, priority: body.priority });
271→      return jsonResponse({ status: "priority_updated", priority: body.priority }, 200);
272→    }
273→
274→    return jsonError(`action '${body.action}' is not valid for entity type '${table}'`, 400);
275→  } catch (error) {
276→    log.error("entity.action.failed", "Entity action failed", error, {
277→      workspaceId,
278→      entityId,
279→      action: body.action,
280→    });
281→    const message = error instanceof Error ? error.message : "entity action failed";
282→    return jsonError(message, 500);
283→  }
284→}
