298→// ---------------------------------------------------------------------------
299→// SSE stream route handler factory
300→// ---------------------------------------------------------------------------
301→
302→export type StreamRouteDeps = {
303→  sseRegistry: SseRegistry;
304→};
305→
306→export function createStreamRouteHandler(deps: StreamRouteDeps) {
307→  const stream: RouteHandler = async (request) => {
308→    const sessionId = request.params.sessionId;
309→
310→    if (!sessionId) {
311→      return jsonError("sessionId is required", 400);
312→    }
313→
314→    const streamId = `stream-${sessionId}`;
315→    return deps.sseRegistry.handleStreamRequest(streamId);
316→  };
317→
318→  return { stream };
319→}
320→
321→// ---------------------------------------------------------------------------
322→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
323→// ---------------------------------------------------------------------------
324→
325→export type OrchestratorWiringDeps = {
326→  surreal: import("surrealdb").Surreal;
327→  shellExec: import("./worktree-manager").ShellExec;
328→  brainBaseUrl: string;
329→  extractionModel: import("../runtime/types").ServerDependencies["extractionModel"];
330→  asSigningKey: import("../oauth/as-key-management").AsSigningKey;
331→  sseRegistry?: SseRegistry;
332→  auth: { api: { getSession: (opts: { headers: Headers }) => Promise<{ user?: { id?: string } } | null> } };
333→  mockAgent: boolean;
334→  sandboxAgentAdapter?: import("./sandbox-adapter").SandboxAgentAdapter;
335→  sandboxAgentType?: string;
336→};
337→
338→export function wireOrchestratorRoutes(
339→  wiringDeps: OrchestratorWiringDeps,
340→): {
341→  assign: RouteHandler;
342→  status: RouteHandler;
343→  accept: RouteHandler;
344→  abort: RouteHandler;
345→  review: RouteHandler;
346→  reject: RouteHandler;
347→  prompt: RouteHandler;
348→  stream?: RouteHandler;
349→} {
350→  const proxyTokenTtlDays = readProxyTokenTtlDays();
351→
352→  const issueProxyTokenForWorkspace = async (
353→    workspaceId: string,
354→    authToken: string,
355→    opts?: { intentRecord?: RecordId<"intent", string>; sessionRecord?: RecordId<"agent_session", string> },
356→  ): Promise<{ proxyToken: string; identityId: string }> => {
357→    const sessionHeaders = new Headers(authToken ? { Cookie: authToken } : undefined);
358→    const session = await wiringDeps.auth.api.getSession({ headers: sessionHeaders });
359→    const personId = session?.user?.id;
360→    if (!personId) {
361→      throw new Error("Failed to issue proxy token: authentication required");
362→    }
363→
364→    const personRecord = new RecordId("person", personId);
365→    const workspaceRecord = new RecordId("workspace", workspaceId);
366→    const [identityRows] = await wiringDeps.surreal.query<[Array<RecordId<"identity", string>>]>(
367→      `SELECT VALUE in FROM member_of WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person) AND out = $ws LIMIT 1;`,
368→      { person: personRecord, ws: workspaceRecord },
369→    );
370→    const identityRecord = identityRows[0];
371→    if (!identityRecord) {
372→      throw new Error(`Failed to issue proxy token: workspace membership required for ${workspaceId}`);
373→    }
374→    const identityId = identityRecord.id as string;
375→
376→    const rawToken = generateProxyToken();
377→    const tokenHash = hashProxyToken(rawToken);
378→    const expiresAt = computeExpiresAt(proxyTokenTtlDays);
379→
380→    const contentFields: Record<string, unknown> = {
381→      token_hash: tokenHash,
382→      workspace: workspaceRecord,
383→      identity: identityRecord,
384→      expires_at: expiresAt,
385→      created_at: new Date(),
386→      revoked: false,
387→    };
388→    if (opts?.intentRecord) {
389→      contentFields.intent = opts.intentRecord;
390→    }
391→    if (opts?.sessionRecord) {
392→      contentFields.session = opts.sessionRecord;
393→    }
394→
395→    await wiringDeps.surreal.query(
396→      `BEGIN TRANSACTION;
397→       UPDATE proxy_token SET revoked = true WHERE identity = $identity AND workspace = $ws AND revoked = false;
398→       CREATE proxy_token CONTENT $content;
399→       COMMIT TRANSACTION;`,
400→      {
401→        identity: identityRecord,
402→        ws: workspaceRecord,
403→        content: contentFields,
404→      },
405→    );
406→
407→    return { proxyToken: rawToken, identityId };
408→  };
409→
410→  const issueBrainMcpAuthEnv = async (
411→    workspaceId: string,
412→    identityId: string,
413→    intentGoal: string,
414→    intentReasoning: string,
415→  ): Promise<{ env: Record<string, string>; intentId: string }> => {
416→    const dpopKeys = await generateKeyPair();
417→    const intentResult = await submitIntentForAuthorization(
418→      {
419→        workspace_id: workspaceId,
420→        identity_id: identityId,
421→        authorization_details: CLI_AUTHORIZATION_DETAILS,
422→        dpop_jwk_thumbprint: dpopKeys.thumbprint,
423→        goal: intentGoal,
424→        reasoning: intentReasoning,
425→      },
426→      {
427→        surreal: wiringDeps.surreal,
428→        extractionModel: wiringDeps.extractionModel,
429→      },
430→    );
431→
432→    let intentStatus: string = intentResult.status;
433→    if (intentStatus === "pending_auth") {
434→      const evaluation = await evaluatePendingIntent(
435→        intentResult.intentId,
436→        {
437→          surreal: wiringDeps.surreal,
438→          extractionModel: wiringDeps.extractionModel,
439→          llmEvaluator: async () => ({
440→            decision: "APPROVE",
441→            risk_score: 0,
442→            reason: "Approved from explicit authenticated orchestrator task assignment",
443→            reasoning:
444→              "User explicitly assigned this task in the orchestrator UI. " +
445→              "Bootstrap MCP token is required to complete the assigned task.",
446→          }),
447→        },
448→      );
449→      if (!evaluation.ok) {
450→        throw new Error(
451→          `Failed to evaluate MCP auth intent: ${evaluation.httpStatus} ${evaluation.error}`,
452→        );
453→      }
454→      intentStatus = evaluation.value.status;
455→    }
456→
457→    if (intentStatus !== "authorized") {
458→      throw new Error(`MCP auth intent is "${intentStatus}" (expected "authorized")`);
459→    }
460→
461→    const tokenResult = await exchangeIntentForToken({
462→      surreal: wiringDeps.surreal,
463→      asSigningKey: wiringDeps.asSigningKey,
464→      intentId: intentResult.intentId,
465→      authorizationDetails: CLI_AUTHORIZATION_DETAILS,
466→      proofThumbprint: dpopKeys.thumbprint,
467→    });
468→
469→    if (!tokenResult.ok) {
470→      throw new Error(
471→        `Failed to exchange MCP auth token: ${tokenResult.httpStatus} ${tokenResult.errorDescription}`,
472→      );
473→    }
474→
475→    const dpopTokenExpiresAt = Math.floor(Date.now() / 1000) + tokenResult.value.expiresIn;
476→
477→    return {
478→      env: {
479→        BRAIN_CLIENT_ID: "orchestrator-session",
480→        BRAIN_ACCESS_TOKEN: "orchestrator-session",
481→        BRAIN_REFRESH_TOKEN: "orchestrator-session",
482→        BRAIN_TOKEN_EXPIRES_AT: String(dpopTokenExpiresAt),
483→        BRAIN_DPOP_PRIVATE_JWK: JSON.stringify(dpopKeys.privateJwk),
484→        BRAIN_DPOP_PUBLIC_JWK: JSON.stringify(dpopKeys.publicJwk),
485→        BRAIN_DPOP_THUMBPRINT: dpopKeys.thumbprint,
486→        BRAIN_DPOP_ACCESS_TOKEN: tokenResult.value.accessToken,
487→        BRAIN_DPOP_TOKEN_EXPIRES_AT: String(dpopTokenExpiresAt),
488→      },
489→      intentId: intentResult.intentId,
490→    };
491→  };
492→
493→  // Workspace access guard — resolves user from session cookie, checks membership
494→  const validateWorkspaceAccess = async (request: Request, workspaceId: string): Promise<Response | undefined> => {
495→    const session = await wiringDeps.auth.api.getSession({ headers: request.headers });
496→    if (!session?.user?.id) {
497→      return jsonError("authentication required", 401);
498→    }
499→    const { RecordId } = await import("surrealdb");
500→    const personRecord = new RecordId("person", session.user.id);
501→    const workspaceRecord = new RecordId("workspace", workspaceId);
502→    // member_of is identity->workspace; resolve person->identity via identity_person subquery
503→    const [memberRows] = await wiringDeps.surreal.query<[Array<{ role: string }>]>(
504→      `SELECT role FROM member_of WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person) AND out = $ws LIMIT 1;`,
505→      { person: personRecord, ws: workspaceRecord },
506→    );
507→    if (!memberRows || memberRows.length === 0) {
508→      return jsonError("not a member of this workspace", 403);
509→    }
510→    return undefined;
511→  };
512→
513→  // Lazy imports to keep module boundary clean
514→  const lifecycleImport = import("./session-lifecycle");
515→  const queriesImport = import("../mcp/mcp-queries");
516→  const guardImport = import("./assignment-guard");
517→  // Helper: resolve repo_path from workspace record
518→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
519→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
520→      `SELECT repo_path FROM $ws;`,
521→      { ws: workspaceRecord },
522→    );
523→    const repoPath = rows[0]?.repo_path;
524→    if (!repoPath) {
525→      throw new Error(`Workspace ${workspaceRecord.id} has no repo_path configured`);
526→    }
527→    return repoPath;
528→  };
529→
530→  const buildTaskScopedIntentContext = async (
531→    taskId: string,
532→  ): Promise<{ goal: string; reasoning: string }> => {
533→    const taskRecord = new RecordId("task", taskId);
534→    const [taskRows] = await wiringDeps.surreal.query<[Array<{ title?: string; description?: string }>]>(
535→      `SELECT title, description FROM $task LIMIT 1;`,
536→      { task: taskRecord },
537→    );
538→    const taskTitle = taskRows[0]?.title?.trim();
539→    const taskDescription = taskRows[0]?.description?.trim();
540→    const taskLabel = taskTitle && taskTitle.length > 0 ? taskTitle : taskId;
541→    const descriptionSuffix = taskDescription && taskDescription.length > 0
542→      ? ` Task description: ${taskDescription}`
543→      : "";
544→
545→    return {
546→      goal: `Complete task: ${taskLabel}`,
547→      reasoning: `Use Brain MCP tools required to complete task "${taskLabel}" in this workspace.${descriptionSuffix}`,
548→    };
549→  };
550→
551→  // Resolve adapter: real SDK adapter from deps, or mock for tests.
552→  // Eagerly resolved when configured; lazy rejection to avoid unhandled promise
553→  // rejections in test suites that don't exercise orchestrator routes.
554→  const resolveAdapter = (): Promise<import("./sandbox-adapter").SandboxAgentAdapter> => {
555→    if (wiringDeps.sandboxAgentAdapter) return Promise.resolve(wiringDeps.sandboxAgentAdapter);
556→    if (wiringDeps.mockAgent) return import("./sandbox-adapter").then((mod) => mod.createMockAdapter());
557→    return Promise.reject(new Error("No sandbox adapter configured — set sandboxAgentAdapter or mockAgent"));
558→  };
559→
560→  const routeDeps: OrchestratorRouteDeps = {
561→    createSession: async (workspaceId, taskId, authToken) => {
562→      const [adapter, lifecycle, queries, guard] = await Promise.all([
563→        resolveAdapter(),
564→        lifecycleImport,
565→        queriesImport,
566→        guardImport,
567→      ]);
568→
569→      // Build task-scoped intent context, issue MCP auth env with intent
570→      const { goal, reasoning } = await buildTaskScopedIntentContext(taskId);
571→      const { identityId } = await issueProxyTokenForWorkspace(workspaceId, authToken);
572→      const mcpAuth = await issueBrainMcpAuthEnv(workspaceId, identityId, goal, reasoning);
573→      const intentRecord = new RecordId("intent", mcpAuth.intentId);
574→
575→      // Issue a governed proxy token (revoke the ungoverned one from issueProxyTokenForWorkspace)
576→      const workspaceRecord = new RecordId("workspace", workspaceId);
577→      const identityRecord = new RecordId("identity", identityId);
578→      const rawToken = generateProxyToken();
579→      const tokenHash = hashProxyToken(rawToken);
580→      const expiresAt = computeExpiresAt(proxyTokenTtlDays);
581→
582→      // Build proxy env for the sandbox agent
583→      const proxyEnv: Record<string, string> = {
584→        ...mcpAuth.env,
585→        ANTHROPIC_BASE_URL: `${wiringDeps.brainBaseUrl}/proxy/llm/anthropic`,
586→        ANTHROPIC_CUSTOM_HEADERS: `X-Brain-Auth: ${rawToken}`,
587→      };
588→
589→      const result = await lifecycle.createOrchestratorSession({
590→        surreal: wiringDeps.surreal,
591→        shellExec: wiringDeps.shellExec,
592→        brainBaseUrl: wiringDeps.brainBaseUrl,
593→        mcpAuthToken: rawToken,
594→        workspaceId,
595→        taskId,
596→        env: proxyEnv,
597→        validateAssignment: guard.validateAssignment,
598→        createAgentSession: queries.createAgentSession,
599→        adapter,
600→        sandboxAgentType: wiringDeps.sandboxAgentType,
601→      });
602→
603→      // After session creation, create the governed proxy token with intent + session
604→      if (result.ok) {
605→        const sessionRecord = new RecordId("agent_session", result.value.agentSessionId);
606→
607→        // Revoke the ungoverned token and create a governed one
608→        await wiringDeps.surreal.query(
609→          `UPDATE proxy_token SET revoked = true WHERE identity = $identity AND workspace = $ws AND revoked = false;`,
610→          { identity: identityRecord, ws: workspaceRecord },
611→        );
612→
613→        const contentFields: Record<string, unknown> = {
614→          token_hash: tokenHash,
615→          workspace: workspaceRecord,
616→          identity: identityRecord,
617→          expires_at: expiresAt,
618→          created_at: new Date(),
619→          revoked: false,
620→          intent: intentRecord,
621→          session: sessionRecord,
622→        };
623→
624→        await wiringDeps.surreal.query(
625→          `CREATE proxy_token CONTENT $content;`,
626→          { content: contentFields },
627→        );
628→      }
629→
630→      // Wire SSE stream + bootstrap prompt on success
631→      if (!result.ok) {
632→        return result;
633→      }
634→
635→      const { agentSessionId, streamId, sessionHandle } = result.value;
636→      const sessionRecord = new RecordId("agent_session", agentSessionId);
637→      const sseRegistry = wiringDeps.sseRegistry;
638→      let emittedActiveStatus = false;
639→      let observedAgentEvent = false;
640→      if (!sessionHandle) {
641→        const cleanup = await lifecycle.abortOrchestratorSession({
642→          surreal: wiringDeps.surreal,
643→          shellExec: wiringDeps.shellExec,
644→          resolveRepoRoot,
645→          sessionId: agentSessionId,
646→          adapter,
647→          endAgentSession: queries.endAgentSession,
648→        });
649→        if (!cleanup.ok) {
650→          log.warn("orchestrator.assign", "Failed to clean up session after missing session handle", {
651→            sessionId: agentSessionId,
652→            error: cleanup.error.message,
653→          });
654→        }
655→        return {
656→          ok: false,
657→          error: {
658→            code: "SESSION_ERROR",
659→            message: `Session ${agentSessionId} was created without a handle - bootstrap failed`,
660→            httpStatus: 500,
661→          },
662→        };
663→      }
664→
665→      if (sseRegistry) {
666→        sseRegistry.registerMessage(streamId);
667→
668→        const { createSandboxEventBridge } = await import("./sandbox-event-bridge");
669→
670→        const bridge = createSandboxEventBridge(
671→          {
672→            emitEvent: sseRegistry.emitEvent,
673→            updateLastEventAt: async (sid) => {
674→              const rec = new RecordId("agent_session", sid);
675→              await wiringDeps.surreal.update(rec).merge({
676→                last_event_at: new Date(),
677→              });
678→            },
679→            updateSessionStatus: async (sid, status, error) => {
680→              const rec = new RecordId("agent_session", sid);
681→              await wiringDeps.surreal.update(rec).merge({
682→                orchestrator_status: status,
683→                last_event_at: new Date(),
684→                ...(error !== undefined ? { error_message: error } : {}),
685→              });
686→            },
687→            notifyStallDetector: () => {
688→              // Stall detector integration deferred to later step
689→            },
690→          },
691→          streamId,
692→          agentSessionId,
693→        );
694→
695→        sessionHandle.onEvent((event) => {
696→          if (event.sender === "agent") {
697→            observedAgentEvent = true;
698→          }
699→          if (!emittedActiveStatus && event.sender === "agent") {
700→            emittedActiveStatus = true;
701→            sseRegistry.emitEvent(streamId, {
702→              type: "agent_status",
703→              sessionId: agentSessionId,
704→              status: "active",
705→            });
706→            wiringDeps.surreal.update(sessionRecord).merge({
707→              orchestrator_status: "active",
708→              last_event_at: new Date(),
709→            }).catch((err) => {
710→              log.warn("orchestrator.assign", "Failed to mark session active after first event", {
711→                sessionId: agentSessionId,
712→                error: String(err),
713→              });
714→            });
715→          }
716→          bridge.handleEvent(event as import("./sandbox-event-bridge").SandboxEvent);
717→        });
718→      }
719→
720→      if (!emittedActiveStatus) {
721→        emittedActiveStatus = true;
722→        if (sseRegistry) {
723→          sseRegistry.emitEvent(streamId, {
724→            type: "agent_status",
725→            sessionId: agentSessionId,
726→            status: "active",
727→          });
728→        }
729→      }
730→      await wiringDeps.surreal.update(sessionRecord).merge({
731→        orchestrator_status: "active",
732→        last_event_at: new Date(),
733→      });
734→
735→      const initialTaskPrompt = `/brain-start-task ${taskId}`;
736→      try {
737→        await sessionHandle.prompt([{ type: "text", text: initialTaskPrompt }]);
738→        if (!observedAgentEvent) {
739→          if (sseRegistry) {
740→            sseRegistry.emitEvent(streamId, {
741→              type: "agent_status",
742→              sessionId: agentSessionId,
743→              status: "idle",
744→            });
745→          }
746→          await wiringDeps.surreal.update(sessionRecord).merge({
747→            orchestrator_status: "idle",
748→            last_event_at: new Date(),
749→          });
750→        }
751→      } catch (err) {
752→        const cleanup = await lifecycle.abortOrchestratorSession({
753→          surreal: wiringDeps.surreal,
754→          shellExec: wiringDeps.shellExec,
755→          resolveRepoRoot,
756→          sessionId: agentSessionId,
757→          adapter,
758→          endAgentSession: queries.endAgentSession,
759→        });
760→        if (!cleanup.ok) {
761→          log.warn("orchestrator.assign", "Failed to clean up session after initial prompt failure", {
762→            sessionId: agentSessionId,
