142→/**
143→ * Validate that a task exists, is in an assignable status, belongs to the
144→ * given workspace, and has no active agent session already working on it.
145→ */
146→export async function validateAssignment(
147→  surreal: Surreal,
148→  workspaceId: string,
149→  taskId: string,
150→): Promise<AssignmentResult> {
151→  // 1. Input validation
152→  if (!taskId) {
153→    return missingTaskId();
154→  }
155→
156→  const taskRecord = new RecordId("task", taskId);
157→
158→  // 2. Task existence
159→  const task = await fetchTask(surreal, taskRecord);
160→  if (!task) {
161→    return taskNotFound(taskId);
162→  }
163→
164→  // 3. Workspace membership
165→  const taskWorkspaceId = task.workspace.id as string;
166→  if (taskWorkspaceId !== workspaceId) {
167→    return workspaceMismatch(taskId);
168→  }
169→
170→  // 4. Repo path required
171→  const repoPath = await fetchWorkspaceRepoPath(surreal, task.workspace);
172→  if (!repoPath) {
173→    return repoPathRequired(workspaceId);
174→  }
175→
176→  // 5. Status eligibility
177→  if (!isAssignableStatus(task.status)) {
178→    return taskNotAssignable(taskId, task.status);
179→  }
180→
181→  // 6. One-agent-per-task
182→  const alreadyActive = await hasActiveSession(surreal, taskRecord);
183→  if (alreadyActive) {
184→    return agentAlreadyActive(taskId);
185→  }
186→
187→  // All checks passed
188→  return {
189→    ok: true,
190→    validation: {
191→      taskRecord,
192→      workspaceRecord: task.workspace,
193→      taskStatus: task.status,
194→      title: task.title,
195→      repoPath,
196→    },
197→  };
198→}
