311→export async function createOrchestratorSession(
312→  input: CreateSessionInput,
313→): Promise<OrchestratorSessionResult> {
314→  // 0. Intent authorization gate (optional — backwards compatible)
315→  if (input.intentId) {
316→    const gateResult = await checkIntentAuthorization(input.surreal, input.intentId, input.workspaceId);
317→    if (!gateResult.ok) {
318→      return { ok: false, error: gateResult.error };
319→    }
320→  }
321→
322→  // 1. Validate assignment eligibility
323→  const assignmentResult = await input.validateAssignment(
324→    input.surreal,
325→    input.workspaceId,
326→    input.taskId,
327→  );
328→
329→  if (!assignmentResult.ok) {
330→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
331→  }
332→
333→  const { validation } = assignmentResult;
334→
335→  return createSessionViaAdapter(input, validation);
336→}
337→
338→// ---------------------------------------------------------------------------
339→// Intent authorization helpers
340→// ---------------------------------------------------------------------------
341→
342→async function checkIntentAuthorization(
343→  surreal: Surreal,
344→  intentId: string,
345→  workspaceId: string,
346→): Promise<SessionResult<void>> {
347→  const intent = await getIntentById(surreal, intentId);
348→  if (!intent) {
349→    return {
350→      ok: false,
351→      error: {
352→        code: "INTENT_NOT_AUTHORIZED",
353→        message: `Intent ${intentId} not found`,
354→        httpStatus: 404,
355→      },
356→    };
357→  }
358→
359→  // Validate workspace scope: intent must belong to the session's workspace
360→  const intentWorkspaceId = intent.workspace.id as string;
361→  if (intentWorkspaceId !== workspaceId) {
362→    return {
363→      ok: false,
364→      error: {
365→        code: "WORKSPACE_MISMATCH",
366→        message: `Intent ${intentId} belongs to workspace "${intentWorkspaceId}", not "${workspaceId}"`,
367→        httpStatus: 403,
368→      },
369→    };
370→  }
371→
372→  const status = intent.status as IntentStatus;
373→  if (status !== "authorized") {
374→    return {
375→      ok: false,
376→      error: {
377→        code: "INTENT_NOT_AUTHORIZED",
378→        message: `Intent ${intentId} has status "${status}", expected "authorized"`,
379→        httpStatus: 403,
380→      },
381→    };
382→  }
383→
384→  return { ok: true, value: undefined as void };
385→}
386→
387→async function transitionIntentToExecuting(
388→  surreal: Surreal,
389→  intentId: string,
390→  sessionRecord: RecordId<"agent_session", string>,
391→): Promise<void> {
392→  await updateIntentStatus(surreal, intentId, "executing");
393→
394→  const intentRecord = new RecordId("intent", intentId);
395→  // NOTE: `$session` is a SurrealDB protected variable — use `$sess` instead
396→  await surreal.query(
397→    "RELATE $intent->gates->$sess SET created_at = time::now();",
398→    { intent: intentRecord, sess: sessionRecord },
399→  );
400→
401→  log.info("orchestrator.intent-gate", "Intent transitioned to executing with gates relation", {
402→    intentId,
403→    sessionId: sessionRecord.id as string,
404→  });
405→}
