422→): Promise<OrchestratorSessionResult> {
423→  const adapter = input.adapter;
424→  const repoRoot = validation.repoPath;
425→  const taskSlug = `${slugFromTitle(validation.title)}-${crypto.randomUUID()}`;
426→
427→  // 1. Create worktree for isolated agent work
428→  const worktreeResult = await createWorktree(
429→    input.shellExec,
430→    repoRoot,
431→    taskSlug,
432→  );
433→
434→  if (!worktreeResult.ok) {
435→    return {
436→      ok: false,
437→      error: worktreeError(worktreeResult.error.message),
438→    };
439→  }
440→
441→  const { branchName, worktreePath } = worktreeResult.value;
442→
443→  // 2. Create agent_session record
444→  const { session_id: agentSessionId } = await input.createAgentSession({
445→    surreal: input.surreal,
446→    agent: "claude",
447→    workspaceRecord: validation.workspaceRecord,
448→    taskId: input.taskId,
